INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9000, 'Slip miejski w Lipianach', 'slip-miejski-w-lipianach-lipiany-9000', 'SLIP', 53.0007028, 14.9686968, 'Zachodniopomorskie', 'Lipiany', 'Dojazd do slipu jest dogodny, prowadzi utwardzoną drogą. Nawierzchnia wykonana z solidnych płyt betonowych zapewnia dobrą przyczepność. W pobliżu slipu znajduje się wystarczająco miejsca na swobodne manewrowanie zestawem z przyczepą. Nośność konstrukcji pozwala na wodowanie jednostek o masie do 3 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9000, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.2, 'Dostępny', FALSE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9001, 'Slip nad jeziorem Jagodne - Jagodne Małe', 'slip-nad-jeziorem-jagodne-jagodne-male-jagodne-male-9001', 'SLIP', 53.9489427, 21.7240407, 'Warmińsko-Mazurskie', 'Jagodne Małe', 'Dojazd do slipu odbywa się drogą gruntową, wymagającą ostrożności. Nawierzchnia żwirowa zapewnia umiarkowaną przyczepność, szczególnie przy większych jednostkach. Miejsce na manewrowanie zestawem jest ograniczone, co wymaga pewnej wprawy. Nośność slipu jest odpowiednia dla łodzi i małych jachtów do 1.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9001, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1, 'Ograniczony', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9002, 'Slip portowy w Łebie', 'slip-portowy-w-lebie-leba-9002', 'SLIP', 54.7603525, 17.5469139, 'Pomorskie', 'Łeba', 'Dojazd do slipu jest bardzo dobry, prowadzi utwardzonymi drogami portowymi. Nawierzchnia betonowa jest solidna i zapewnia doskonałą przyczepność w każdych warunkach. Dostępne jest obszerne miejsce do manewrowania zestawem, nawet dla dużych łodzi. Slip jest przystosowany do wodowania jednostek o masie do 5 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9002, 'Czynny', 'Publiczny', 'Płatny', 'Całodobowo', 'Betonowy', 'Umiarkowane', NULL, 2, 'Na terenie obiektu', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9003, 'Slip miejski - Marina Pogoń, Szczecin', 'slip-miejski-marina-pogon-szczecin-szczecin-9003', 'SLIP', 53.4190165, 14.5597927, 'Zachodniopomorskie', 'Szczecin', 'Dojazd do slipu jest dobry, ale przez teren miejski, co wymaga uwagi. Nawierzchnia wykonana z solidnych płyt betonowych gwarantuje stabilność i przyczepność. Miejsce na manewrowanie zestawem jest ograniczone, co może wymagać pewnej wprawy od operatora. Slip jest przystosowany do wodowania jednostek o masie do 4 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9003, 'Czynny', 'Dla klientów', 'W cenie usługi', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.8, 'Na terenie obiektu', TRUE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9004, 'Slip rekreacyjny w Bobrowie', 'slip-rekreacyjny-w-bobrowie-bobrowo-9004', 'SLIP', 53.539688, 16.0935172, 'Zachodniopomorskie', 'Bobrowo', 'Dojazd do slipu jest drogą gruntową, wymagającą ostrożności, szczególnie po opadach. Nawierzchnia piaszczysta może być śliska, zaleca się napęd 4x4 dla większych jednostek. Miejsce na manewrowanie zestawem jest ograniczone, co może sprawić trudności. Nośność slipu jest odpowiednia dla małych łodzi i skuterów wodnych do 1 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9004, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Piaszczysty', 'Łagodne', NULL, 0.8, 'Ograniczony', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9005, 'Slip prywatny - Zegrze Południowe', 'slip-prywatny-zegrze-poludniowe-zegrze-poludniowe-9005', 'SLIP', 52.4482227, 21.0071795, 'Mazowieckie', 'Zegrze Południowe', 'Dojazd do slipu jest utwardzony, lecz wymaga ostrożności ze względu na ograniczoną przestrzeń. Nawierzchnia slipu wykonana jest z betonu, zapewniając solidną przyczepność. Dostępne jest wąskie miejsce do manewrowania zestawem, co wymaga wprawy. Konstrukcja slipu jest przystosowana do wodowania jednostek o masie do 3.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9005, 'Czynny', 'Prywatny', 'Płatny', 'Całodobowo', 'Betonowy', 'Umiarkowane', NULL, 1.8, 'Na terenie obiektu', TRUE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9006, 'Slip dla klientów - Zegrze Południowe', 'slip-dla-klientow-zegrze-poludniowe-zegrze-poludniowe-9006', 'SLIP', 52.4559419, 21.0142112, 'Mazowieckie', 'Zegrze Południowe', 'Dojazd do slipu jest komfortowy, z szeroką drogą dojazdową. Nawierzchnia slipu wykonana jest z płyt betonowych, gwarantując stabilność. Dostępne jest dużo miejsca do manewrowania zestawem, co ułatwia operacje. Konstrukcja slipu jest przystosowana do wodowania jednostek o masie do 5 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9006, 'Czynny', 'Dla klientów', 'W cenie usługi', 'Całodobowo', 'Płyty betonowe', 'Łagodne', NULL, 2.2, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9007, 'Slip miejski - Toruń', 'slip-miejski-torun-torun-9007', 'SLIP', 53.0047531, 18.5652162, 'Kujawsko-Pomorskie', 'Toruń', 'Dojazd do slipu jest możliwy, jednak droga jest częściowo uszkodzona. Nawierzchnia slipu jest asfaltowa, obecnie w trakcie remontu, co może wpływać na przyczepność. Miejsce do manewrowania zestawem jest ograniczone i wymaga wprawy. Konstrukcja slipu jest projektowana dla jednostek o masie do 4 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9007, 'W remoncie', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Asfaltowy', 'Umiarkowane', NULL, 1.5, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9008, 'Slip rekreacyjny - Zarzecze', 'slip-rekreacyjny-zarzecze-zarzecze-9008', 'SLIP', 49.7242417, 19.1845009, 'Śląskie', 'Zarzecze', 'Dojazd do slipu prowadzi drogą gruntową, która może być trudna po opadach deszczu. Nawierzchnia slipu jest żwirowa, co wymaga ostrożności przy wodowaniu. Dostępne jest wąskie miejsce do manewrowania zestawem, co utrudnia operacje. Konstrukcja slipu jest przeznaczona dla mniejszych jednostek o masie do 2 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9008, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Strome', NULL, 1.2, 'Brak', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9009, 'Slip miejski - Kraków', 'slip-miejski-krakow-krakow-9009', 'SLIP', 50.0372857, 19.9116516, 'Małopolskie', 'Kraków', 'Dojazd do slipu jest bardzo dobry, z utwardzoną drogą i czytelnym oznakowaniem. Nawierzchnia slipu wykonana jest z solidnego betonu, zapewniając doskonałą przyczepność. Dostępne jest dużo miejsca do manewrowania zestawem, co znacznie ułatwia wodowanie. Konstrukcja slipu jest przystosowana do wodowania jednostek o masie do 6 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9009, 'Czynny', 'Publiczny', 'Płatny', 'Całodobowo', 'Betonowy', 'Łagodne', NULL, 2.5, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9010, 'Slip Paprotki - Jezioro Złotnickie', 'slip-paprotki-jezioro-zlotnickie-paprotki-9010', 'SLIP', 50.7228768, 15.9456054, 'Dolnośląskie', 'Paprotki', 'Do slipu prowadzi utwardzona droga gruntowa, łatwo dostępna dla pojazdów z przyczepą. Nawierzchnia slipu jest żwirowa, co zapewnia dobrą przyczepność. Miejsce na zestaw jest ograniczone, wymaga precyzyjnego manewrowania. Nośność slipu pozwala na wodowanie jednostek o masie do 1500 kg.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9010, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Umiarkowane', NULL, 1.2, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9011, 'Slip Stary Kostrzynek - Rzeka Odra', 'slip-stary-kostrzynek-rzeka-odra-stary-kostrzynek-9011', 'SLIP', 52.8312611, 14.1516476, 'Lubuskie', 'Stary Kostrzynek', 'Dojazd do slipu jest komfortowy, drogą asfaltową, z wystarczającą przestrzenią do zawracania. Nawierzchnia wykonana jest z solidnych płyt betonowych, zapewniających stabilność. Dostępne jest dużo miejsca na zestaw, co ułatwia wodowanie większych łodzi. Slip jest przystosowany do wodowania jednostek o masie do 3000 kg.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9011, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Łagodne', NULL, 1.8, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9012, 'Slip Mielno - Jezioro Jamno', 'slip-mielno-jezioro-jamno-mielno-9012', 'SLIP', 54.2765403, 16.180661, 'Zachodniopomorskie', 'Mielno', 'Slip znajduje się przy głównej drodze, z łatwym dojazdem i dobrą widocznością. Nawierzchnia jest betonowa, w dobrym stanie, zapewniająca pewne wodowanie. Na terenie obiektu jest dużo miejsca na manewrowanie zestawem. Nośność slipu pozwala na wodowanie jednostek o masie do 2500 kg.', NULL);
