INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9013, 'Slip Gdynia - Marina', 'slip-gdynia-marina-gdynia-9013', 'SLIP', 54.5178849, 18.550739, 'Pomorskie', 'Gdynia', 'Dojazd do slipu jest bardzo dobry, drogą utwardzoną w obrębie mariny, z szerokimi zakrętami. Nawierzchnia slipu jest solidna, betonowa, idealna do intensywnego użytkowania. Dostępne jest dużo miejsca na manewrowanie zestawem, co ułatwia operacje. Slip jest przystosowany do wodowania jednostek o masie do 4000 kg.', NULL);
