INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9014, 'Slip Włocławek - Wisła', 'slip-wloclawek-wisla-wloclawek-9014', 'SLIP', 52.6647729, 19.0617937, 'Kujawsko-Pomorskie', 'Włocławek', 'Dojazd do slipu jest możliwy drogą gruntową, jednak wymaga ostrożności ze względu na nierówności. Nawierzchnia slipu jest asfaltowa, częściowo uszkodzona, co utrudnia wodowanie. Miejsce na zestaw jest wąskie, co wymaga dużej wprawy od kierowcy. Nośność slipu jest ograniczona, zalecana dla jednostek do 1000 kg.', NULL);
