INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9044, 'Slip nad Wisłą - Sandomierz', 'slip-nad-wisla-sandomierz-sandomierz-9044', 'SLIP', 50.674652, 21.7480193, 'Świętokrzyskie', 'Sandomierz', 'Dojazd drogą gruntową, bezpośrednio do brzegu rzeki. Nawierzchnia slipu piaszczysta, naturalna, wymaga ostrożności. Dostępne obszerne miejsce do manewrowania zestawem. Nośność slipu ograniczona do małych i lekkich jednostek.', NULL);
