INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9045, 'Slip Żywiec - Jezioro Żywieckie', 'slip-zywiec-jezioro-zywieckie-zywiec-9045', 'SLIP', 49.7162291, 19.2087944, 'Śląskie', 'Żywiec', 'Dojazd do slipu jest utwardzony i łatwy, prowadzi bezpośrednio do brzegu jeziora. Nawierzchnia slipu wykonana jest z solidnego betonu, zapewniającego dobrą przyczepność. Dostępne jest obszerne miejsce do manewrowania zestawem z przyczepą. Konstrukcja zapewnia wysoką nośność, odpowiednią dla większości jednostek pływających.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9045, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Betonowy', 'Umiarkowane', NULL, 1.8, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9046, 'Slip Pomorze - Wisła', 'slip-pomorze-wisla-pomorze-9046', 'SLIP', 51.1978455, 21.9330179, 'Lubelskie', 'Pomorze', 'Dojazd do slipu jest częściowo gruntowy, wymaga ostrożności, zwłaszcza po opadach. Nawierzchnia slipu to utwardzony żwir, który może być śliski. Miejsce do manewrowania zestawem jest ograniczone, wymaga wprawy. Nośność slipu jest wystarczająca dla mniejszych i średnich jednostek.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9046, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1.2, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9047, 'Slip Ryn - Jezioro Ryńskie (Północny)', 'slip-ryn-jezioro-rynskie-polnocny-ryn-9047', 'SLIP', 53.9300789, 21.5317873, 'Warmińsko-Mazurskie', 'Ryn', 'Dojazd do slipu jest bardzo dobry, drogą asfaltową. Nawierzchnia slipu składa się z solidnych płyt betonowych, zapewniających stabilność. Dostępne jest dużo miejsca na przygotowanie i wodowanie zestawu. Slip charakteryzuje się wysoką nośnością, odpowiednią dla dużych łodzi.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9047, 'Czynny', 'Publiczny', 'Płatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 2, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9048, 'Slip Ryn - Jezioro Ryńskie (Południowy)', 'slip-ryn-jezioro-rynskie-poludniowy-ryn-9048', 'SLIP', 53.9368212, 21.54315, 'Warmińsko-Mazurskie', 'Ryn', 'Dojazd do slipu jest utwardzony, prowadzi przez teren obiektu. Nawierzchnia slipu jest asfaltowa, dobrze utrzymana. Miejsce do manewrowania zestawem jest nieco wąskie, wymaga precyzji. Nośność konstrukcji jest dobra, przystosowana do średnich i większych jednostek.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9048, 'Czynny', 'Dla klientów', 'W cenie usługi', 'Całodobowo', 'Asfaltowy', 'Umiarkowane', NULL, 1.7, 'Na terenie obiektu', TRUE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9049, 'Slip Żywiec - Przystań Harcerska', 'slip-zywiec-przystan-harcerska-zywiec-9049', 'SLIP', 49.7386098, 19.213662, 'Śląskie', 'Żywiec', 'Dojazd do slipu jest gruntowy, może być utrudniony. Nawierzchnia slipu to piaszczysta plaża, co ogranicza możliwości wodowania. Brak wydzielonego miejsca do manewrowania zestawem, wymaga dużej wprawy. Nośność jest niska, przeznaczona wyłącznie dla małych łodzi i kajaków.', NULL);
