INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9050, 'Slip Jezioro Dębiec - Nowy Dębiec', 'slip-jezioro-debiec-nowy-debiec-nowy-debiec-9050', 'SLIP', 52.0033752, 16.7007851, 'Wielkopolskie', 'Nowy Dębiec', 'Dojazd drogą utwardzoną, dobrze utrzymaną. Nawierzchnia slipu to płyty betonowe, zapewniające dobrą przyczepność w każdych warunkach. Dostępne jest obszerne miejsce na zestaw pojazd-przyczepa, co ułatwia manewrowanie. Nośność konstrukcji pozwala na bezpieczne wodowanie jednostek do 3 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9050, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.8, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9051, 'Slip Rzeka Warta - Jankowice', 'slip-rzeka-warta-jankowice-jankowice-9051', 'SLIP', 51.0438147, 19.2290215, 'Łódzkie', 'Jankowice', 'Dojazd drogą gruntową, ostatni odcinek wymaga ostrożności, szczególnie po opadach. Nawierzchnia slipu to żwir z elementami betonu, co zapewnia umiarkowaną stabilność. Miejsce na zestaw jest ograniczone, wymaga precyzyjnego manewrowania. Nośność szacowana na 1.5 tony, odpowiednia dla mniejszych łodzi.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9051, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9052, 'Slip Klub Żeglarski - Poznań', 'slip-klub-zeglarski-poznan-poznan-9052', 'SLIP', 52.4739945, 16.7816865, 'Wielkopolskie', 'Poznań', 'Dojazd asfaltową drogą osiedlową, dobrze utrzymaną i oznakowaną. Nawierzchnia slipu to solidny beton, zapewniający doskonałą przyczepność i trwałość. Dostępne jest wystarczające miejsce na zestaw, jednak teren jest ogrodzony i monitorowany. Nośność slipu wynosi do 5 ton, co pozwala na wodowanie większych jednostek.', NULL);
