INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9053, 'Slip Jezioro Głowieńskie - Głowno', 'slip-jezioro-glowienskie-glowno-glowno-9053', 'SLIP', 51.962953, 19.7152966, 'Łódzkie', 'Głowno', 'Dojazd drogą szutrową, wymagającą uwagi w deszczowe dni ze względu na błoto. Nawierzchnia slipu to utwardzony piasek z elementami trawy, co może utrudniać wodowanie cięższych jednostek. Miejsce na zestaw jest ograniczone, ale wystarczające dla mniejszych łodzi. Nośność do 1 tony, zalecany dla lekkich jednostek.', NULL);
