INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9054, 'Slip Port Jachtowy - Świnoujście', 'slip-port-jachtowy-swinoujscie-swinoujscie-9054', 'SLIP', 53.8545357, 14.303176, 'Zachodniopomorskie', 'Świnoujście', 'Dojazd drogą asfaltową, doskonale oznakowaną i łatwą do odnalezienia. Nawierzchnia slipu to wysokiej jakości płyty betonowe, przystosowane do dużych obciążeń i intensywnego użytkowania. Dostępne jest obszerne miejsce do manewrowania zestawem, również dla dużych przyczep i jachtów. Nośność slipu przekracza 8 ton, co umożliwia wodowanie ciężkich jednostek.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9054, 'Czynny', 'Dla klientów', 'Płatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 2.5, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
