INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9062, 'Slip z płyt betonowych - Mielno', 'slip-z-plyt-betonowych-mielno-mielno-9062', 'SLIP', 54.2510699, 16.1451401, 'Zachodniopomorskie', 'Mielno', 'Dojazd do slipu jest asfaltowy, łatwy i dobrze oznakowany. Nawierzchnia wykonana jest z solidnych płyt betonowych, zapewniających doskonałą przyczepność. Dostępne jest dużo miejsca na swobodne manewrowanie zestawem z przyczepą. Slip charakteryzuje się wysoką nośnością, odpowiednią dla jednostek do 3 ton.', NULL);
