INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9063, 'Slip betonowy - Grochowo Drugie', 'slip-betonowy-grochowo-drugie-grochowo-drugie-9063', 'SLIP', 54.3235705, 19.1814451, 'Pomorskie', 'Grochowo Drugie', 'Dojazd do slipu jest utwardzony, prowadzi przez teren obiektu. Nawierzchnia slipu jest betonowa, w dobrym stanie technicznym. Manewrowanie zestawem wymaga wprawy ze względu na ograniczoną przestrzeń. Nośność slipu pozwala na wodowanie jednostek o masie do 2.5 tony.', NULL);
