INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9064, 'Slip asfaltowy - Działoszyn', 'slip-asfaltowy-dzialoszyn-dzialoszyn-9064', 'SLIP', 51.1127288, 18.8761793, 'Łódzkie', 'Działoszyn', 'Dojazd do slipu jest drogą asfaltową, jednak wymaga remontu. Nawierzchnia slipu jest asfaltowa, z widocznymi ubytkami i nierównościami. Miejsce na manewrowanie zestawem jest wąskie, co utrudnia operacje. Nośność slipu jest ograniczona, zalecana dla jednostek do 1.5 tony.', NULL);
