INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9086, 'Slip żwirowy - Łaszewo', 'slip-zwirowy-laszewo-laszewo-9086', 'SLIP', 53.1694302, 15.5524642, 'Zachodniopomorskie', 'Łaszewo', 'Dojazd do slipu drogą gruntową, wymagający ostrożności w deszczowe dni. Nawierzchnia żwirowa, stabilna, ale może wymagać napędu 4x4 przy cięższych łodziach. Miejsce na manewrowanie zestawem jest ograniczone, wymaga wprawy. Nośność slipu jest odpowiednia dla małych i średnich jednostek do 1.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9086, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1.2, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9087, 'Slip asfaltowy - Karpin', 'slip-asfaltowy-karpin-karpin-9087', 'SLIP', 53.1800964, 15.694202, 'Zachodniopomorskie', 'Karpin', 'Dojazd do slipu drogą asfaltową, łatwy i komfortowy. Nawierzchnia slipu asfaltowa, w dobrym stanie, zapewniająca płynne wodowanie. Dostępne jest wystarczające miejsce do manewrowania zestawem z przyczepą. Slip przystosowany do wodowania jednostek o masie do 2.5 tony.', NULL);
