INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9088, 'Slip piaszczysty - Chełpa', 'slip-piaszczysty-chelpa-chelpa-9088', 'SLIP', 53.1885955, 15.4995773, 'Zachodniopomorskie', 'Chełpa', 'Dojazd do slipu drogą polną, może być problematyczny po opadach deszczu. Nawierzchnia piaszczysta, wymaga ostrożności i najlepiej napędu 4x4. Miejsce na manewrowanie jest ograniczone, szczególnie dla większych zestawów. Nośność slipu jest niska, przeznaczony dla małych łodzi i skuterów wodnych do 1 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9088, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Piaszczysty', 'Łagodne', NULL, 1, 'Brak', FALSE, NULL, 'Wąsko', NULL);
