INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9105, 'Slip gminny - Dominikowo', 'slip-gminny-dominikowo-dominikowo-9105', 'SLIP', 53.2112918, 15.8372012, 'Zachodniopomorskie', 'Dominikowo', 'Dojazd do slipu jest utwardzony, prowadzi bezpośrednio z drogi gminnej. Nawierzchnia slipu wykonana jest z płyt betonowych, zapewniających dobrą przyczepność. Na terenie obiektu dostępny jest obszerny parking dla zestawów z przyczepami. Nośność konstrukcji pozwala na wodowanie jednostek o masie do 3 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9105, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Betonowy', 'Umiarkowane', NULL, 1.2, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9106, 'Slip miejski - Drawno', 'slip-miejski-drawno-drawno-9106', 'SLIP', 53.213374, 15.7491835, 'Zachodniopomorskie', 'Drawno', 'Dojazd do slipu jest wąski, wymaga ostrożności, ale jest utwardzony. Nawierzchnia wykonana z płyt betonowych, miejscami nierówna. Parking dla przyczep jest ograniczony do kilku miejsc w pobliżu. Slip przystosowany do wodowania łodzi o masie do 2 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9106, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Łagodne', NULL, 1, 'Ograniczony', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9107, 'Slip przy przystani - Drawno', 'slip-przy-przystani-drawno-drawno-9107', 'SLIP', 53.2163329, 15.7613626, 'Zachodniopomorskie', 'Drawno', 'Dojazd do slipu jest dobrze oznakowany i utwardzony, prowadzi przez teren przystani. Nawierzchnia betonowa, w dobrym stanie technicznym, zapewnia stabilność. Dostępny jest duży parking dla zestawów, monitorowany przez obsługę. Slip umożliwia wodowanie jednostek o masie do 4 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9107, 'Czynny', 'Dla klientów', 'W cenie usługi', 'Całodobowo', 'Betonowy', 'Umiarkowane', NULL, 1.8, 'Na terenie obiektu', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9108, 'Slip wiejski - Żółwino', 'slip-wiejski-zolwino-zolwino-9108', 'SLIP', 53.2960356, 15.7114651, 'Zachodniopomorskie', 'Żółwino', 'Dojazd do slipu jest polną drogą, w złym stanie, szczególnie po opadach. Nawierzchnia żwirowa, niestabilna, wymaga napędu 4x4. Brak wydzielonego miejsca na parking dla przyczep, możliwy postój na poboczu. Slip przeznaczony dla małych łodzi, nośność do 1 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9108, 'W remoncie', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Strome', NULL, 0.8, 'Brak', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9109, 'Slip prywatny - Żółwino', 'slip-prywatny-zolwino-zolwino-9109', 'SLIP', 53.2963327, 15.7114866, 'Zachodniopomorskie', 'Żółwino', 'Dojazd do slipu jest utwardzony, prowadzi przez teren prywatny, dostęp po uiszczeniu opłaty. Nawierzchnia piaszczysta, dobrze ubita, ale wymaga uwagi przy wodowaniu cięższych jednostek. Dostępny jest przestronny parking dla zestawów, monitorowany. Slip przystosowany do wodowania jednostek o masie do 2.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9109, 'Czynny', 'Prywatny', 'Płatny', 'Całodobowo', 'Piaszczysty', 'Łagodne', NULL, 1.3, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9110, 'Slip betonowy - Starzyce', 'slip-betonowy-starzyce-starzyce-9110', 'SLIP', 53.0476732, 15.6333477, 'Zachodniopomorskie', 'Starzyce', 'Dojazd do slipu jest utwardzony, prowadzi przez lokalną drogę. Nawierzchnia slipu wykonana jest z solidnych płyt betonowych, zapewniających dobrą przyczepność. Obok slipu dostępny jest ograniczony obszar do manewrowania zestawem. Nośność konstrukcji pozwala na wodowanie jednostek o masie do 3 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9110, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.8, 'Ograniczony', TRUE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9111, 'Slip rekreacyjny - Wapnica Zachód', 'slip-rekreacyjny-wapnica-zachod-wapnica-9111', 'SLIP', 53.2783078, 15.4671845, 'Zachodniopomorskie', 'Wapnica', 'Dojazd do slipu jest łatwy, bezpośrednio z drogi wojewódzkiej. Nawierzchnia slipu to dobrze utrzymany asfalt, zapewniający płynne wodowanie. W pobliżu slipu znajduje się przestronny plac, idealny do manewrowania zestawem. Slip przystosowany jest do wodowania łodzi o masie do 2.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9111, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Asfaltowy', 'Łagodne', NULL, 1.5, 'Dostępny', FALSE, NULL, 'Dużo miejsca', NULL);
