INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9112, 'Czynny', 'Dla klientów', 'Płatny', 'Całodobowo', 'Betonowy', 'Umiarkowane', NULL, 2, 'Na terenie obiektu', TRUE, NULL, 'Wymaga wprawy', NULL);
