INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9125, 'Slip miejski w Pełczycach', 'slip-miejski-w-pelczycach-pelczyce-9125', 'SLIP', 53.0483312, 15.3035468, 'Zachodniopomorskie', 'Pełczyce', 'Dojazd do slipu jest utwardzony, prowadzi drogą gminną. Nawierzchnia slipu wykonana jest z płyt betonowych, zapewniając dobrą przyczepność. W pobliżu dostępny jest obszerny plac manewrowy, umożliwiający swobodne operowanie zestawem z przyczepą. Konstrukcja slipu jest solidna, przystosowana do wodowania jednostek o masie do 3 ton.', NULL);
