INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9147, 'Slip rekreacyjny - Dołżyna', 'slip-rekreacyjny-dolzyna-dolzyna-9147', 'SLIP', 53.1052345, 15.7437283, 'Lubuskie', 'Dołżyna', 'Dojazd do slipu odbywa się drogą gruntową, wymagającą ostrożności, szczególnie po opadach. Nawierzchnia slipu jest żwirowa, z elementami utwardzenia, co może utrudniać wodowanie cięższych jednostek. Miejsce na zestaw jest wystarczające, ale nierówne. Slip przeznaczony jest dla małych i średnich łodzi, o maksymalnej masie 1.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9147, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Umiarkowane', NULL, 0.9, 'Brak', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9148, 'Slip leśny - Bukowie', 'slip-lesny-bukowie-bukowie-9148', 'SLIP', 53.089777, 15.6684143, 'Lubuskie', 'Bukowie', 'Dojazd do slipu prowadzi przez leśną drogę szutrową, dostępną dla pojazdów terenowych lub z napędem 4x4. Nawierzchnia slipu to utwardzona trawa z elementami piasku, co może być śliskie. Miejsce na zestaw jest ograniczone, wymaga precyzji i doświadczenia. Slip nadaje się do wodowania lekkich łodzi i kajaków, do 0.8 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9148, 'Nieczynny', 'Prywatny', 'W cenie usługi', 'Całodobowo', 'Trawa', 'Strome', NULL, 0.7, 'Na terenie obiektu', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9149, 'Slip ośrodka - Bukowie', 'slip-osrodka-bukowie-bukowie-9149', 'SLIP', 53.0921923, 15.6660781, 'Lubuskie', 'Bukowie', 'Dojazd do slipu jest asfaltowy, dobrze oznakowany, prowadzący bezpośrednio do ośrodka wypoczynkowego. Nawierzchnia slipu to solidny beton, zapewniający doskonałą przyczepność w każdych warunkach. Dostępne jest obszerne miejsce na zestaw, z wydzielonym parkingiem dla przyczep. Slip umożliwia wodowanie jednostek o masie do 2.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9149, 'Czynny', 'Dla klientów', 'W cenie usługi', 'Całodobowo', 'Betonowy', 'Łagodne', NULL, 1.4, 'Na terenie obiektu', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9150, 'Slip betonowy - Piaseczno', 'slip-betonowy-piaseczno-piaseczno-9150', 'SLIP', 53.099794, 15.8370545, 'Zachodniopomorskie', 'Piaseczno', 'Dojazd do slipu drogą utwardzoną, ostatnie 50 metrów szutrem. Nawierzchnia slipu wykonana z płyt betonowych, zapewniająca dobrą przyczepność. W pobliżu dostępny jest obszerny plac manewrowy dla zestawów z przyczepą. Konstrukcja slipu przystosowana do wodowania jednostek o masie do 3 ton.', NULL);
