INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9167, 'Czynny', 'Dla klientów', 'W cenie usługi', 'Całodobowo', 'Piaszczysty', 'Umiarkowane', NULL, 1.2, 'Na terenie obiektu', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9168, 'Slip rybacki - Jastarnia', 'slip-rybacki-jastarnia-jastarnia-9168', 'SLIP', 54.6968239, 18.67576, 'Pomorskie', 'Jastarnia', 'Dojazd do slipu jest łatwy, bezpośrednio z drogi asfaltowej, z wydzielonym pasem. Nawierzchnia slipu wykonana jest z solidnych płyt betonowych, odpornych na warunki morskie. Dostępne jest dużo miejsca na zestaw, co ułatwia operacje. Nośność konstrukcji pozwala na wodowanie jednostek o masie do 6 ton.', NULL);
