INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9169, 'Slip gminny - Krzynki (Jezioro Krzynki)', 'slip-gminny-krzynki-jezioro-krzynki-krzynki-9169', 'SLIP', 52.9935752, 15.3529958, 'Lubuskie', 'Krzynki', 'Dojazd do slipu drogą gruntową, wymagającą ostrożności w deszczowe dni. Nawierzchnia slipu jest żwirowa, co zapewnia dobrą przyczepność. Miejsce na zestaw jest ograniczone, ale wystarczające dla mniejszych łodzi. Nośność slipu jest odpowiednia dla jednostek o masie do 2 ton.', NULL);
