INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9171, 'Slip żwirowy - Młyny Strachockie', 'slip-zwirowy-mlyny-strachockie-mlyny-strachockie-9171', 'SLIP', 51.851026, 18.6758375, 'Wielkopolskie', 'Młyny Strachockie', 'Dojazd do slipu drogą gruntową, może być utrudniony po opadach. Nawierzchnia żwirowa, wymaga ostrożności przy wodowaniu cięższych jednostek. Miejsce na manewrowanie jest ograniczone, wymaga wprawy. Maksymalna nośność slipu szacowana na 1.5 tony.', NULL);
