INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9174, 'Slip betonowy - Jastarnia (Port)', 'slip-betonowy-jastarnia-port-jastarnia-9174', 'SLIP', 54.733164, 18.5818835, 'Pomorskie', 'Jastarnia', 'Dojazd do slipu drogą brukowaną, w obrębie portu. Nawierzchnia betonowa, w bardzo dobrym stanie, idealna do wodowania. Dostępne jest dużo miejsca na manewrowanie zestawem, nawet w sezonie. Obiekt przystosowany do wodowania jednostek o masie do 5 ton.', NULL);
