INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9175, 'Slip portowy - Jastarnia', 'slip-portowy-jastarnia-jastarnia-9175', 'SLIP', 54.7333217, 18.5814056, 'Pomorskie', 'Jastarnia', 'Dojazd do slipu jest utwardzony i dobrze oznakowany, prowadzi bezpośrednio z głównej drogi. Nawierzchnia slipu wykonana jest z solidnych płyt betonowych, zapewniających dobrą przyczepność. Dostępne jest obszerne miejsce do manewrowania zestawem oraz parking dla przyczep. Slip jest przystosowany do wodowania jednostek o masie do 3 ton.', NULL);
