INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9176, 'Slip nad Zalewem Sulejowskim - Smardzewice', 'slip-nad-zalewem-sulejowskim-smardzewice-smardzewice-9176', 'SLIP', 51.4687569, 20.008931, 'Łódzkie', 'Smardzewice', 'Dojazd do slipu odbywa się drogą gruntową, która w deszczowe dni może być śliska. Nawierzchnia slipu jest żwirowa, co wymaga ostrożności podczas wodowania. Miejsce na zestaw jest ograniczone, co może utrudniać manewrowanie większymi przyczepami. Slip jest odpowiedni dla małych i średnich łodzi, do 1.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9176, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1.2, 'Ograniczony', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9177, 'Slip rzeczny - Gassy', 'slip-rzeczny-gassy-gassy-9177', 'SLIP', 52.0788209, 21.2123301, 'Mazowieckie', 'Gassy', 'Dojazd do slipu jest nieutwardzony i prowadzi przez teren zielony, co może być wyzwaniem dla pojazdów z napędem na jedną oś. Nawierzchnia slipu to trawa, która przy dużej wilgotności może być bardzo śliska. Brak dedykowanego miejsca na zestaw, manewrowanie wymaga dużej wprawy. Slip przeznaczony jest dla lekkich jednostek, kajaków i małych łodzi do 500 kg.', NULL);
