INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9209, 'Slip leśny - Wronka', 'slip-lesny-wronka-wronka-9209', 'SLIP', 54.0341303, 21.7193933, 'Warmińsko-Mazurskie', 'Wronka', 'Dojazd do slipu jest utrudniony, prowadzi wąską, nieutwardzoną drogą leśną. Nawierzchnia piaszczysta może być niestabilna, szczególnie po opadach deszczu. Miejsce do manewrowania zestawem jest bardzo wąskie i wymaga dużej precyzji. Nośność slipu jest ograniczona, przeznaczona dla lekkich łodzi.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9209, 'W remoncie', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Piaszczysty', 'Strome', NULL, 1, 'Brak', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9210, 'Slip betonowy - Szwecja', 'slip-betonowy-szwecja-szwecja-9210', 'SLIP', 53.3435421, 16.5703278, 'Zachodniopomorskie', 'Szwecja', 'Dojazd do slipu jest utwardzony, prowadzi bezpośrednio z drogi gminnej. Nawierzchnia slipu wykonana jest z solidnych płyt betonowych, zapewniających dobrą przyczepność. W pobliżu dostępny jest obszerny plac manewrowy, umożliwiający łatwe operowanie zestawem z przyczepą. Konstrukcja slipu przewidziana jest dla jednostek o masie do 3 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9210, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.8, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9211, 'Slip miejski - Wałcz, Jezioro Raduń', 'slip-miejski-walcz-jezioro-radun-walcz-9211', 'SLIP', 53.2680618, 16.4839205, 'Zachodniopomorskie', 'Wałcz', 'Dojazd do slipu odbywa się drogą gruntową, wymagającą ostrożności w deszczowe dni. Nawierzchnia slipu to utwardzony żwir z elementami piasku, co zapewnia stabilność. Miejsce na zestaw z przyczepą jest ograniczone, wymaga precyzyjnego manewrowania. Slip przystosowany jest do wodowania mniejszych jednostek o masie do 1.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9211, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1.2, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9212, 'Slip przy przystani - Wałcz', 'slip-przy-przystani-walcz-walcz-9212', 'SLIP', 53.2693915, 16.4773186, 'Zachodniopomorskie', 'Wałcz', 'Dojazd do slipu jest asfaltowy, łatwy i komfortowy. Nawierzchnia slipu to solidny beton, zapewniający doskonałą przyczepność. Parking dla przyczep dostępny jest na terenie przyległego obiektu, co ułatwia logistykę. Slip przeznaczony jest dla jednostek o masie do 2.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9212, 'Czynny', 'Dla klientów', 'W cenie usługi', 'Całodobowo', 'Betonowy', 'Umiarkowane', NULL, 1.5, 'Na terenie obiektu', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9213, 'Slip rekreacyjny - Wałcz', 'slip-rekreacyjny-walcz-walcz-9213', 'SLIP', 53.2715892, 16.4726889, 'Zachodniopomorskie', 'Wałcz', 'Dojazd do slipu prowadzi przez parkową aleję, z ograniczonym ruchem. Nawierzchnia slipu jest piaszczysta, co może utrudniać wodowanie cięższych łodzi. Brak dedykowanego miejsca na parking przyczep w bezpośrednim sąsiedztwie. Slip nadaje się do wodowania kajaków i małych łodzi wiosłowych o masie do 0.5 tony.', NULL);
