INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9214, 'Slip portowy - Wałcz', 'slip-portowy-walcz-walcz-9214', 'SLIP', 53.2739956, 16.4575582, 'Zachodniopomorskie', 'Wałcz', 'Dojazd do slipu jest dobrze oznakowany, z bezpośrednim dostępem z drogi wojewódzkiej. Nawierzchnia slipu to solidny asfalt, zapewniający doskonałą przyczepność. Dostępny jest duży parking dla przyczep, oddalony o kilkadziesiąt metrów. Slip jest przystosowany do wodowania jednostek o masie do 4 ton.', NULL);
