INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9216, 'Slip żwirowy - Świnoujście Karsibór', 'slip-zwirowy-swinoujscie-karsibor-swinoujscie-9216', 'SLIP', 53.9106942, 14.2658937, 'Zachodniopomorskie', 'Świnoujście', 'Dojazd do slipu odbywa się drogą utwardzoną, miejscami nierówną. Nawierzchnia slipu jest żwirowa, co wymaga ostrożności przy wodowaniu. Miejsce na zestaw jest ograniczone, co może utrudniać manewrowanie większymi przyczepami. Nośność slipu pozwala na wodowanie mniejszych łodzi i skuterów wodnych.', NULL);
