INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9228, 'Slip portowy - Jastarnia', 'slip-portowy-jastarnia-jastarnia-9228', 'SLIP', 54.7276072, 18.5979503, 'Pomorskie', 'Jastarnia', 'Dojazd do slipu jest bardzo dobry, bezpośrednio z drogi utwardzonej. Nawierzchnia slipu jest betonowa, w bardzo dobrym stanie technicznym, regularnie konserwowana. Parking dla zestawów z przyczepą jest dostępny na terenie portu, z dużą ilością miejsca do manewrowania. Slip przystosowany jest do wodowania dużych jednostek, o masie do 10 ton, z głębokością końcową około 2.5 metra.', NULL);
