INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9229, 'Slip wiejski - Kawka', 'slip-wiejski-kawka-kawka-9229', 'SLIP', 54.197392, 16.8908597, 'Zachodniopomorskie', 'Kawka', 'Dojazd do slipu jest utrudniony, prowadzi nieutwardzoną drogą polną. Nawierzchnia slipu jest piaszczysta i niestabilna, co uniemożliwia bezpieczne wodowanie. Brak dedykowanego parkingu dla zestawów z przyczepą w pobliżu. Slip jest obecnie nieczynny i nie nadaje się do użytku, z bardzo płytką głębokością końcową około 0.5 metra.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9229, 'Nieczynny', 'Prywatny', 'Płatny', 'Całodobowo', 'Piaszczysty', 'Łagodne', NULL, 0.5, 'Brak', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9230, 'Slip miejski - Iława Jeziorak', 'slip-miejski-ilawa-jeziorak-ilawa-9230', 'SLIP', 53.5995124, 19.5431167, 'Warmińsko-Mazurskie', 'Iława', 'Dojazd do slipu jest utwardzony, prowadzi bezpośrednio z drogi asfaltowej. Nawierzchnia slipu wykonana jest z płyt betonowych, zapewniających dobrą przyczepność. Dostępne jest dużo miejsca na swobodne manewrowanie zestawem z przyczepą. Nośność konstrukcji pozwala na wodowanie jednostek o masie do 3 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9230, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.8, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9231, 'Slip przystani - Iława Mały Jeziorak', 'slip-przystani-ilawa-maly-jeziorak-ilawa-9231', 'SLIP', 53.6149726, 19.5630661, 'Warmińsko-Mazurskie', 'Iława', 'Dojazd do slipu odbywa się drogą szutrową, wymagającą ostrożności. Nawierzchnia slipu to beton, miejscami z drobnymi ubytkami. Miejsce na zestaw jest ograniczone, co wymaga wprawy przy manewrowaniu. Slip przeznaczony jest dla jednostek o masie do 2 ton.', NULL);
