INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9232, 'Slip rzeczny - Szczucin Wisła', 'slip-rzeczny-szczucin-wisla-szczucin-9232', 'SLIP', 50.3246093, 21.0757748, 'Małopolskie', 'Szczucin', 'Dojazd do slipu jest polną drogą, która może być błotnista po opadach. Nawierzchnia slipu to utwardzony żwir, wymagający uwagi przy wodowaniu. Dostępne jest ograniczone miejsce na manewrowanie zestawem, szczególnie w sezonie. Nośność slipu szacowana jest na około 1.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9232, 'W remoncie', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Strome', NULL, 1, 'Brak', FALSE, NULL, 'Wąsko', NULL);
