INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9250, 'Czynny', 'Publiczny', 'Płatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.8, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9251, 'Slip żwirowy - Modrzewo Kolonia', 'slip-zwirowy-modrzewo-kolonia-modrzewo-kolonia-9251', 'SLIP', 53.3121287, 15.4564186, 'Zachodniopomorskie', 'Modrzewo Kolonia', 'Dojazd do slipu odbywa się drogą gruntową, wymagającą ostrożności w deszczowe dni. Nawierzchnia jest żwirowa, co zapewnia naturalne przejście do wody. Miejsce na zestaw jest ograniczone, zaleca się wcześniejsze rozpoznanie terenu. Slip przeznaczony jest dla mniejszych jednostek, o maksymalnej wadze do 1.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9251, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
