INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9271, 'Slip miejski - Kołobrzeg Port', 'slip-miejski-kolobrzeg-port-kolobrzeg-9271', 'SLIP', 54.1786071, 15.5362814, 'Zachodniopomorskie', 'Kołobrzeg', 'Dojazd drogą utwardzoną, możliwy ruch portowy. Nawierzchnia z płyt betonowych, solidna i równa. Miejsce na zestaw jest ograniczone, wymaga precyzji. Slip przystosowany do wodowania ciężkich jednostek, do 5 ton.', NULL);
