INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9272, 'Slip wędkarski - Kołobrzeg Dźwirzyno', 'slip-wedkarski-kolobrzeg-dzwirzyno-kolobrzeg-9272', 'SLIP', 54.1718955, 15.5152671, 'Zachodniopomorskie', 'Kołobrzeg', 'Dojazd drogą gruntową, obecnie w remoncie. Nawierzchnia żwirowa, wymaga utwardzenia. Dostępne jest miejsce na zestaw, ale manewrowanie jest utrudnione. Nośność szacowana na 1.5 tony, po remoncie wzrośnie.', NULL);
