INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9273, 'Slip hotelowy - Kołobrzeg Wschód', 'slip-hotelowy-kolobrzeg-wschod-kolobrzeg-9273', 'SLIP', 54.1965657, 15.6430591, 'Zachodniopomorskie', 'Kołobrzeg', 'Dojazd asfaltowy, bardzo komfortowy. Nawierzchnia betonowa, idealnie gładka i bezpieczna. Dużo miejsca do swobodnego manewrowania zestawem. Slip zaprojektowany dla jednostek do 4 ton.', NULL);
