INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9274, 'Slip gminny - Sianożęty Plaża', 'slip-gminny-sianozety-plaza-sianozety-9274', 'SLIP', 54.2140118, 15.7421658, 'Zachodniopomorskie', 'Sianożęty', 'Dojazd drogą polną, piaszczystą. Nawierzchnia slipu piaszczysta, niestabilna. Brak wydzielonego miejsca na zestaw, parkowanie utrudnione. Nośność ograniczona, zalecane dla lekkich łodzi do 1 tony.', NULL);
