INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9275, 'Slip Portowy - Ustronie Morskie', 'slip-portowy-ustronie-morskie-ustronie-morskie-9275', 'SLIP', 54.2198899, 15.7665842, 'Zachodniopomorskie', 'Ustronie Morskie', 'Dojazd do slipu jest utwardzony, prowadzi bezpośrednio do brzegu. Nawierzchnia slipu to solidny beton, zapewniający dobrą przyczepność. Dostępne jest obszerne miejsce do manewrowania zestawem samochód-przyczepa. Konstrukcja slipu jest przystosowana do obsługi jednostek o masie do 3 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9275, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Betonowy', 'Umiarkowane', NULL, 1.8, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9276, 'Slip nad Kanałem - Łasin Koszaliński', 'slip-nad-kanalem-lasin-koszalinski-lasin-koszalinski-9276', 'SLIP', 54.2288129, 15.7985756, 'Zachodniopomorskie', 'Łasin Koszaliński', 'Dojazd do slipu odbywa się drogą gruntową, wymagającą ostrożności. Nawierzchnia składa się z płyt betonowych, które mogą być nierówne. Miejsce na zestaw jest ograniczone, co wymaga precyzji przy manewrowaniu. Slip jest przeznaczony dla mniejszych jednostek, o maksymalnej masie do 1,5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9276, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Łagodne', NULL, 1.2, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
