INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9292, 'Slip Złocieniec - Jezioro Siecino', 'slip-zlocieniec-jezioro-siecino-gmina-zlocieniec-9292', 'SLIP', 53.4733622, 15.8885191, 'Zachodniopomorskie', 'gmina Złocieniec', 'Dojazd do slipu asfaltową drogą gminną, w bardzo dobrym stanie. Nawierzchnia to solidny beton, zapewniający stabilność. Miejsce na zestaw z przyczepą jest wystarczające, choć wymaga uwagi przy większych jednostkach. Nośność slipu szacowana jest na 2 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9292, 'Czynny', 'Publiczny', 'Płatny', 'Całodobowo', 'Betonowy', 'Umiarkowane', NULL, 1.7, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9293, 'Slip Suliszewo - Marina', 'slip-suliszewo-marina-suliszewo-9293', 'SLIP', 53.5186896, 15.9213702, 'Zachodniopomorskie', 'Suliszewo', 'Dojazd do slipu drogą wewnętrzną mariny, wyłożoną kostką brukową. Nawierzchnia slipu to specjalistyczne płyty betonowe, antypoślizgowe. Dostępne jest ograniczone miejsce na manewrowanie zestawem, co wymaga wprawy. Maksymalna nośność slipu wynosi 4 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9293, 'W remoncie', 'Tylko dla członków klubu', 'W cenie usługi', 'Całodobowo', 'Płyty betonowe', 'Strome', NULL, 2.2, 'Na terenie obiektu', TRUE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9294, 'Slip Oleszno - Plaża Gminna', 'slip-oleszno-plaza-gminna-oleszno-9294', 'SLIP', 53.4754846, 15.7746172, 'Zachodniopomorskie', 'Oleszno', 'Dojazd do slipu drogą polną, w sezonie letnim dobrze utrzymaną. Nawierzchnia to utwardzony żwir z elementami piasku. Miejsce na zestaw z przyczepą jest ograniczone, ale wystarczające dla mniejszych łodzi. Nośność slipu jest niska, do 1,5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9294, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1.2, 'Brak', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9295, 'Slip betonowy - Złocieniec', 'slip-betonowy-zlocieniec-gmina-zlocieniec-9295', 'SLIP', 53.4629727, 15.8891358, 'Zachodniopomorskie', 'gmina Złocieniec', 'Dojazd do slipu jest łatwy, prowadzi drogą utwardzoną. Nawierzchnia slipu wykonana jest z solidnych płyt betonowych, zapewniających dobrą przyczepność. W pobliżu slipu dostępny jest obszerny plac manewrowy, umożliwiający swobodne operowanie zestawem z przyczepą. Konstrukcja slipu jest przystosowana do wodowania jednostek o masie do 3 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9295, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.8, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9296, 'Slip żwirowy - Gudowo', 'slip-zwirowy-gudowo-gudowo-9296', 'SLIP', 53.4885351, 15.8789109, 'Zachodniopomorskie', 'Gudowo', 'Dojazd do slipu odbywa się drogą gruntową, wymagającą ostrożności. Nawierzchnia slipu jest żwirowa, co zapewnia naturalne wtopienie w krajobraz. Miejsca na manewrowanie zestawem jest niewiele, zalecana jest precyzja. Slip przystosowany jest do wodowania mniejszych łodzi i skuterów wodnych, o masie do 1.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9296, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1.2, 'Ograniczony', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9297, 'Slip dla klientów - Suliszewo', 'slip-dla-klientow-suliszewo-suliszewo-9297', 'SLIP', 53.5344742, 15.9257288, 'Zachodniopomorskie', 'Suliszewo', 'Dojazd do slipu jest dobrze oznakowany i prowadzi bezpośrednio z głównej drogi. Slip wykonany jest z solidnych płyt betonowych, zapewniających stabilność i trwałość. Na terenie obiektu dostępny jest przestronny parking oraz plac manewrowy dla zestawów z przyczepami. Konstrukcja slipu umożliwia bezpieczne wodowanie jednostek o masie do 4 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9297, 'Czynny', 'Dla klientów', 'W cenie usługi', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 2, 'Na terenie obiektu', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9298, 'Slip piaszczysty - Nętno', 'slip-piaszczysty-netno-netno-9298', 'SLIP', 53.6263592, 15.8058248, 'Zachodniopomorskie', 'Nętno', 'Dojazd do slipu jest nieutwardzony, prowadzi przez leśną ścieżkę. Nawierzchnia slipu jest piaszczysta, co wymaga ostrożności przy wodowaniu. Brak wydzielonego miejsca na parking dla przyczep, manewrowanie jest utrudnione. Slip przeznaczony jest głównie do wodowania kajaków, pontonów i małych łodzi o masie do 0.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9298, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Piaszczysty', 'Łagodne', NULL, 1, 'Brak', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9299, 'Slip asfaltowy - Dołgie', 'slip-asfaltowy-dolgie-dolgie-9299', 'SLIP', 53.6096333, 15.9183973, 'Zachodniopomorskie', 'Dołgie', 'Dojazd do slipu jest asfaltowy, jednak obecnie teren jest objęty remontem. Nawierzchnia slipu wykonana jest z asfaltu, co zapewnia dobrą przyczepność w normalnych warunkach. Dostępny jest parking dla przyczep, ale manewrowanie może być utrudnione ze względu na stromy spadek. Slip jest projektowany do obsługi jednostek o masie do 2.5 tony, po zakończeniu remontu.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9299, 'W remoncie', 'Publiczny', 'Płatny', 'Całodobowo', 'Asfaltowy', 'Strome', NULL, 1.7, 'Dostępny', TRUE, NULL, 'Wąsko', NULL);
