INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9313, 'Slip miejski - Resko Północ', 'slip-miejski-resko-polnoc-resko-9313', 'SLIP', 53.7735168, 15.396871, 'Zachodniopomorskie', 'Resko', 'Dojazd do slipu odbywa się drogą szutrową, wymagającą ostrożności. Nawierzchnia slipu jest żwirowa, co może wymagać napędu 4x4. Brak dedykowanego miejsca na parkowanie przyczepy, należy szukać w okolicy. Nośność slipu jest ograniczona, do 1.5 tony, dla mniejszych łodzi.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9313, 'W remoncie', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Strome', NULL, 0.8, 'Brak', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9314, 'Slip rekreacyjny - Resko Południe', 'slip-rekreacyjny-resko-poludnie-resko-9314', 'SLIP', 53.7717082, 15.401868, 'Zachodniopomorskie', 'Resko', 'Dojazd do slipu jest łatwy, drogą utwardzoną. Nawierzchnia slipu to trawa wzmocniona, odpowiednia dla lekkich jednostek. Na terenie obiektu dostępne jest ograniczone miejsce na zestaw holowniczy. Slip jest przeznaczony dla jednostek o masie do 1 tony.', NULL);
