INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9315, 'Slip betonowy - Port Stepnica', 'slip-betonowy-port-stepnica-stepnica-9315', 'SLIP', 53.6508213, 14.6198236, 'Zachodniopomorskie', 'Stepnica', 'Dojazd do slipu drogą utwardzoną, łatwy dla zestawów z przyczepą. Nawierzchnia wykonana z solidnych płyt betonowych, zapewniająca dobrą przyczepność. W pobliżu dostępny jest obszerny plac manewrowy, umożliwiający swobodne operowanie. Nośność konstrukcji przewidziana jest dla jednostek o masie do 3,5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9315, 'Czynny', 'Publiczny', 'Płatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.8, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9316, 'Slip żwirowy - Jezioro Rosnowskie', 'slip-zwirowy-jezioro-rosnowskie-cybulino-9316', 'SLIP', 53.809538, 16.2476912, 'Zachodniopomorskie', 'Cybulino', 'Dojazd do slipu drogą gruntową, wymagający ostrożności w deszczowe dni. Nawierzchnia żwirowa, stabilna, ale może być śliska dla napędu 2WD. Miejsce na zestaw jest ograniczone, zaleca się wcześniejsze rozpoznanie terenu. Nośność slipu jest wystarczająca dla mniejszych łodzi i skuterów wodnych.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9316, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1.2, 'Ograniczony', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9317, 'Slip betonowy - Zalew Sulejowski', 'slip-betonowy-zalew-sulejowski-smardzewice-9317', 'SLIP', 51.4732686, 19.9981798, 'Łódzkie', 'Smardzewice', 'Dojazd do slipu asfaltowy, bardzo dobry, bez problemów dla dużych zestawów. Nawierzchnia betonowa, w dobrym stanie, zapewnia pewne wodowanie. Dostępne jest obszerne miejsce do manewrowania i przygotowania jednostki. Slip przystosowany do wodowania jednostek o masie do 5 ton.', NULL);
