INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9333, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1, 'Dostępny', FALSE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9334, 'Slip wędkarski - Prężyce Zachód', 'slip-wedkarski-prezyce-zachod-prezyce-9334', 'SLIP', 51.2472625, 16.8340294, 'Dolnośląskie', 'Prężyce', 'Dojazd do slipu jest wąski i wymaga precyzji, prowadzi przez teren prywatny. Nawierzchnia trawiasta, bardzo śliska w deszczu, utrudnia wodowanie. Miejsce na zestaw jest bardzo ograniczone, co wymaga dużej wprawy. Slip przeznaczony dla małych łodzi wędkarskich o masie do 1 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9334, 'W remoncie', 'Tylko dla członków klubu', 'Płatny', 'Całodobowo', 'Trawa', 'Strome', NULL, 0.8, 'Brak', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9335, 'Slip Port Czerniakowski - Warszawa', 'slip-port-czerniakowski-warszawa-warszawa-9335', 'SLIP', 52.2270935, 21.0435261, 'Mazowieckie', 'Warszawa', 'Do slipu prowadzi utwardzona droga dojazdowa, zapewniająca łatwy dostęp dla zestawów. Nawierzchnia slipu jest betonowa, w dobrym stanie technicznym, co gwarantuje stabilność. Dostępne jest obszerne miejsce do manewrowania zestawem, co ułatwia wodowanie i wyciąganie jednostek. Nośność konstrukcji jest przystosowana do większości typowych jednostek pływających.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9335, 'Czynny', 'Publiczny', 'Płatny', 'Całodobowo', 'Betonowy', 'Umiarkowane', NULL, 1.8, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9336, 'Slip Jezioro Niegocin - Wilkasy', 'slip-jezioro-niegocin-wilkasy-wilkasy-9336', 'SLIP', 54.0309228, 21.7259915, 'Warmińsko-Mazurskie', 'Wilkasy', 'Dojazd do slipu jest komfortowy, drogą asfaltową, z łatwym dostępem dla pojazdów z przyczepami. Nawierzchnia wykonana jest z solidnych płyt betonowych, zapewniających dobrą przyczepność. Wokół slipu znajduje się wystarczająca przestrzeń do swobodnego manewrowania zestawem. Konstrukcja slipu jest wytrzymała i przystosowana do wodowania łodzi motorowych oraz jachtów.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9336, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Łagodne', NULL, 1.2, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9337, 'Slip Rzeka Wisła - Most Łazienkowski', 'slip-rzeka-wisla-most-lazienkowski-warszawa-9337', 'SLIP', 52.2206959, 21.0668736, 'Mazowieckie', 'Warszawa', 'Dojazd do slipu jest możliwy drogą gruntową, wymagającą ostrożności, szczególnie po opadach. Nawierzchnia slipu jest żwirowa, co może wymagać napędu 4x4 przy większych jednostkach. Miejsce do manewrowania zestawem jest ograniczone, co wymaga pewnej wprawy od kierowcy. Nośność slipu jest odpowiednia dla mniejszych i średnich łodzi.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9337, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Umiarkowane', NULL, 1, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9338, 'Slip Przystań Wodna - Saska Kępa', 'slip-przystan-wodna-saska-kepa-warszawa-9338', 'SLIP', 52.2208057, 21.0687418, 'Mazowieckie', 'Warszawa', 'Dojazd do slipu jest wygodny, drogą utwardzoną, bezpośrednio na teren przystani. Nawierzchnia slipu jest solidna, betonowa, zapewniająca bezpieczne wodowanie. Dostępne jest wystarczające miejsce do manewrowania zestawem, co ułatwia obsługę. Nośność slipu jest wysoka, przystosowana do różnorodnych jednostek pływających.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9338, 'Czynny', 'Dla klientów', 'W cenie usługi', 'Całodobowo', 'Betonowy', 'Umiarkowane', NULL, 1.5, 'Na terenie obiektu', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9339, 'Slip Pływający - Bulwary Wiślane', 'slip-plywajacy-bulwary-wislane-warszawa-9339', 'SLIP', 52.2215113, 21.0631213, 'Mazowieckie', 'Warszawa', 'Dojazd do slipu jest łatwy, zlokalizowany w pobliżu bulwarów, jednak bez bezpośredniego wjazdu na samą konstrukcję. Nawierzchnia slipu to płyty betonowe na konstrukcji pływającej, dostosowującej się do poziomu wody. Miejsce do manewrowania jest ograniczone ze względu na miejską lokalizację. Nośność jest odpowiednia dla mniejszych jednostek i skuterów wodnych.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9339, 'W remoncie', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Łagodne', NULL, 0.8, 'Brak', TRUE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9340, 'Slip betonowy - Łomianki Dolne', 'slip-betonowy-lomianki-dolne-lomianki-dolne-9340', 'SLIP', 52.3308403, 20.9242077, 'Mazowieckie', 'Łomianki Dolne', 'Dojazd do slipu drogą utwardzoną, ostatnie 50 metrów to droga szutrowa. Nawierzchnia slipu wykonana jest z płyt betonowych, zapewniając dobrą przyczepność. Dostępne jest obszerne miejsce do manewrowania zestawem z przyczepą. Nośność slipu pozwala na wodowanie jednostek o masie do 3 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9340, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.8, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9341, 'Slip żwirowy - Jezioro Trzciniec', 'slip-zwirowy-jezioro-trzciniec-trzciniec-9341', 'SLIP', 53.51037, 16.3005462, 'Zachodniopomorskie', 'Trzciniec', 'Dojazd do slipu prowadzi polną drogą, wymagającą ostrożności w deszczowe dni. Nawierzchnia slipu jest żwirowa, co może wymagać napędu 4x4 dla cięższych jednostek. Miejsce na zestaw jest ograniczone, zaleca się wcześniejsze przygotowanie. Nośność slipu szacowana jest na jednostki do 1.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9341, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1.2, 'Ograniczony', FALSE, NULL, 'Wąsko', NULL);
