INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9343, 'Slip piaszczysty - Broczyno', 'slip-piaszczysty-broczyno-broczyno-9343', 'SLIP', 53.5253772, 16.3043923, 'Zachodniopomorskie', 'Broczyno', 'Dojazd do slipu prowadzi przez leśną drogę, która może być trudna po opadach deszczu. Nawierzchnia slipu jest piaszczysta, co wymaga ostrożności i doświadczenia przy wodowaniu. Miejsce na zestaw jest ograniczone i wymaga wprawy w manewrowaniu. Nośność slipu jest niska, przeznaczony dla małych łodzi do 1 tony.', NULL);
