INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9347, 'Slip prywatny Czaplinek - Ośrodek Wypoczynkowy', 'slip-prywatny-czaplinek-osrodek-wypoczynkowy-czaplinek-9347', 'SLIP', 53.5497109, 16.2506512, 'Zachodniopomorskie', 'Czaplinek', 'Dojazd drogą utwardzoną, zlokalizowany na terenie ośrodka wypoczynkowego. Nawierzchnia slipu to utwardzony żwir, stabilny i dobrze utrzymany. Miejsce na zestaw jest wystarczające, ale wymaga uwagi. Nośność slipu szacowana jest na 2.0 tony.', NULL);
