INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9351, 'Slip żwirowy - Czarne Wielkie', 'slip-zwirowy-czarne-wielkie-czarne-wielkie-9351', 'SLIP', 53.6519813, 16.2799245, 'Zachodniopomorskie', 'Czarne Wielkie', 'Dojazd do slipu odbywa się polną drogą, która może być wymagająca po opadach deszczu. Nawierzchnia slipu to utwardzony żwir z elementami piasku, co wymaga ostrożności. Miejsce na zestaw jest ograniczone, zaleca się precyzyjne manewrowanie. Slip przeznaczony jest głównie dla mniejszych łodzi i skuterów wodnych, o maksymalnej masie do 1.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9351, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1.2, 'Ograniczony', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9352, 'Slip miejski - Złocieniec', 'slip-miejski-zlocieniec-zlocieniec-9352', 'SLIP', 53.5577397, 16.0564998, 'Zachodniopomorskie', 'Złocieniec', 'Dojazd do slipu jest bardzo dobry, bezpośrednio z drogi asfaltowej, z łatwym dostępem. Nawierzchnia slipu to solidny beton, zapewniający stabilność i bezpieczeństwo. Dostępne jest obszerne miejsce do manewrowania zestawem, idealne nawet dla większych przyczep. Slip jest przystosowany do wodowania jednostek o masie do 4 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9352, 'Czynny', 'Publiczny', 'Płatny', 'Całodobowo', 'Betonowy', 'Umiarkowane', NULL, 2, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9353, 'Slip leśny - Psie Głowy', 'slip-lesny-psie-glowy-psie-glowy-9353', 'SLIP', 53.5018842, 16.2394811, 'Zachodniopomorskie', 'Psie Głowy', 'Dojazd do slipu prowadzi przez leśną drogę gruntową, która może być wyzwaniem dla pojazdów z napędem na jedną oś. Nawierzchnia slipu jest piaszczysta z elementami trawy, co wymaga ostrożności. Miejsce na zestaw jest bardzo ograniczone, wymaga dużej wprawy w manewrowaniu. Slip jest odpowiedni dla małych łodzi i kajaków, o maksymalnej masie do 1 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9353, 'Nieczynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Piaszczysty', 'Strome', NULL, 0.8, 'Brak', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9354, 'Slip prywatny - Ostroróg', 'slip-prywatny-ostrorog-ostrorog-9354', 'SLIP', 53.5372549, 16.4114457, 'Wielkopolskie', 'Ostroróg', 'Dojazd do slipu jest utwardzony, ale wąski, prowadzi przez teren prywatny. Nawierzchnia slipu wykonana jest z płyt betonowych, w dobrym stanie technicznym. Miejsce na zestaw jest wystarczające, ale wymaga uwagi ze względu na otoczenie. Slip przeznaczony jest dla jednostek o masie do 2.5 tony, dostępny wyłącznie dla klientów obiektu.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9354, 'Czynny', 'Dla klientów', 'W cenie usługi', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.5, 'Na terenie obiektu', TRUE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9355, 'Slip betonowy - Machliny', 'slip-betonowy-machliny-machliny-9355', 'SLIP', 53.4789575, 16.3486632, 'Zachodniopomorskie', 'Machliny', 'Dojazd drogą utwardzoną, ostatnie 50 metrów szutrem. Nawierzchnia slipu to płyty betonowe, w dobrym stanie. Miejsce na zestaw z przyczepą jest ograniczone, wymaga ostrożności. Nośność slipu pozwala na wodowanie jednostek do 2 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9355, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.2, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9356, 'Slip żwirowy - Machliny (Wschodni)', 'slip-zwirowy-machliny-wschodni-machliny-9356', 'SLIP', 53.4808278, 16.3516508, 'Zachodniopomorskie', 'Machliny', 'Dojazd polną drogą, zalecany dla pojazdów 4x4. Nawierzchnia slipu żwirowa, stabilna, ale nierówna. Dostępne jest dużo miejsca na manewrowanie zestawem. Nośność slipu jest wystarczająca dla łodzi do 1.5 tony.', NULL);
