INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9374, 'Slip turystyczny - Kazimierz Dolny', 'slip-turystyczny-kazimierz-dolny-kazimierz-dolny-9374', 'SLIP', 51.3230242, 21.9415381, 'Lubelskie', 'Kazimierz Dolny', 'Dojazd do slipu jest dobrze oznakowany, prowadzi drogą szutrową. Nawierzchnia slipu jest żwirowa, co wymaga ostrożności przy wodowaniu. Dostępne jest wystarczająco miejsca na terenie obiektu do manewrowania zestawem. Slip jest przystosowany do wodowania jednostek o masie do 1,5 tony.', NULL);
