INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9375, 'Slip Portowy - Giżycko', 'slip-portowy-gizycko-gizycko-9375', 'SLIP', 54.0326669, 21.7639221, 'Warmińsko-Mazurskie', 'Giżycko', 'Dojazd do slipu jest utwardzony, prowadzi bezpośrednio z drogi wojewódzkiej. Nawierzchnia slipu wykonana jest z płyt betonowych, zapewniających dobrą przyczepność. Obok slipu znajduje się obszerne miejsce do manewrowania zestawem oraz parking dla przyczep. Nośność konstrukcji pozwala na wodowanie jednostek o masie do 3 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9375, 'Czynny', 'Publiczny', 'Płatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.8, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
