INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9400, 'Slip betonowy - Radzyny', 'slip-betonowy-radzyny-radzyny-9400', 'SLIP', 52.5464891, 16.5796772, 'Wielkopolskie', 'Radzyny', 'Dojazd do slipu jest łatwy, prowadzi utwardzoną drogą. Nawierzchnia slipu wykonana jest z solidnego betonu, zapewniając dobrą przyczepność. Dostępne jest obszerne miejsce na zestaw pojazd-przyczepa. Nośność konstrukcji pozwala na wodowanie jednostek o masie do 3 ton.', NULL);
