INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9401, 'Slip portowy - Dziwnów (Wschodni)', 'slip-portowy-dziwnow-wschodni-dziwnow-9401', 'SLIP', 54.020705, 14.7416976, 'Zachodniopomorskie', 'Dziwnów', 'Obiekt położony jest w porcie, z dobrym dojazdem asfaltową drogą. Nawierzchnia slipu to wytrzymałe płyty betonowe, idealne do intensywnego użytkowania. Na terenie portu znajduje się dedykowane miejsce na zestaw do wodowania. Slip jest przystosowany do wodowania jednostek o masie do 5 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9401, 'Czynny', 'Publiczny', 'Płatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.8, 'Na terenie obiektu', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9402, 'Slip dla wędkarzy - Dziwnów (Zachodni)', 'slip-dla-wedkarzy-dziwnow-zachodni-dziwnow-9402', 'SLIP', 54.0212798, 14.7380029, 'Zachodniopomorskie', 'Dziwnów', 'Dojazd do slipu jest możliwy drogą gruntową, wymaga ostrożności. Nawierzchnia wykonana jest z betonu, zapewniając stabilność. Miejsce na zestaw pojazd-przyczepa jest ograniczone, co wymaga precyzji. Slip jest przeznaczony dla mniejszych jednostek, o nośności do 2 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9402, 'Czynny', 'Dla klientów', 'W cenie usługi', 'Całodobowo', 'Betonowy', 'Łagodne', NULL, 1.5, 'Ograniczony', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9403, 'Slip rzeczny - Sromowce Niżne', 'slip-rzeczny-sromowce-nizne-sromowce-nizne-9403', 'SLIP', 49.3987034, 20.414381, 'Małopolskie', 'Sromowce Niżne', 'Dojazd do slipu jest wyzwaniem, prowadzi wąską, szutrową drogą. Nawierzchnia slipu to utwardzony żwir, który może być śliski. Brak wydzielonego miejsca na zestaw, co utrudnia manewrowanie. Slip jest odpowiedni dla lekkich łodzi, o nośności do 1 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9403, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Strome', NULL, 0.8, 'Brak', FALSE, NULL, 'Wymaga wprawy', NULL);
