INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9405, 'Slip betonowy - Śwignajno Małe', 'slip-betonowy-swignajno-male-swignajno-male-9405', 'SLIP', 53.6915342, 21.5104079, 'Warmińsko-Mazurskie', 'Śwignajno Małe', 'Dojazd drogą utwardzoną, ostatnie 50m szutrem. Nawierzchnia slipu wykonana z solidnych płyt betonowych, zapewniających dobrą przyczepność. Dostępne jest obszerne miejsce na zestaw pojazd-przyczepa, ułatwiające manewrowanie. Nośność slipu pozwala na wodowanie jednostek o masie do 3 ton.', NULL);
