INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9407, 'Slip Zielony Lasek - Jezioro Ryńskie', 'slip-zielony-lasek-jezioro-rynskie-zielony-lasek-9407', 'SLIP', 53.8754287, 21.5935206, 'Warmińsko-Mazurskie', 'Zielony Lasek', 'Dojazd polną drogą, wymagany napęd 4x4 w deszczu. Nawierzchnia żwirowa, niestabilna, z licznymi ubytkami. Brak wydzielonego miejsca na zestaw, parkowanie wzdłuż drogi. Nośność ograniczona, zalecane dla małych jednostek do 1 tony.', NULL);
