INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9408, 'Slip Piekło - Wisła', 'slip-pieklo-wisla-pieklo-9408', 'SLIP', 53.9315694, 18.8628853, 'Pomorskie', 'Piekło', 'Dojazd drogą gruntową, dobrze utrzymaną. Nawierzchnia piaszczysta, utwardzona, z tendencją do zapadania się przy dużym obciążeniu. Dostępne jest obszerne miejsce do zawracania i parkowania przyczepy. Slip przystosowany do wodowania jednostek o masie do 2,5 tony.', NULL);
