INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9409, 'Slip Wielki Lubień - Jezioro Warlubskie', 'slip-wielki-lubien-jezioro-warlubskie-wielki-lubien-9409', 'SLIP', 53.5149449, 18.7480086, 'Kujawsko-Pomorskie', 'Wielki Lubień', 'Dojazd przez teren ośrodka, droga utwardzona. Nawierzchnia trawiasta, wzmocniona geokratą, dobrze utrzymana. Miejsce na zestaw jest ograniczone, wymaga ostrożności przy manewrowaniu. Nośność slipu pozwala na wodowanie jednostek do 1,5 tony.', NULL);
