INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9410, 'Slip z płyt betonowych - Międzychód', 'slip-z-plyt-betonowych-miedzychod-miedzychod-9410', 'SLIP', 52.6074736, 15.8988048, 'Wielkopolskie', 'Międzychód', 'Dojazd do slipu jest komfortowy, prowadzi utwardzoną drogą gminną, z łatwym dostępem. Nawierzchnia slipu wykonana jest z solidnych płyt betonowych, zapewniających stabilność i dobrą przyczepność. W bezpośrednim sąsiedztwie slipu znajduje się przestronny plac manewrowy, idealny do operowania dużymi zestawami. Konstrukcja slipu umożliwia bezpieczne wodowanie jednostek o masie do 4 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9410, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Łagodne', NULL, 1.8, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9411, 'Slip żwirowy - Kleszczewo', 'slip-zwirowy-kleszczewo-kleszczewo-9411', 'SLIP', 53.9632574, 21.8376675, 'Warmińsko-Mazurskie', 'Kleszczewo', 'Dojazd do slipu odbywa się drogą gruntową, wymagającą ostrożności, szczególnie w deszczowe dni. Nawierzchnia slipu jest żwirowa, dobrze utwardzona, ale może być śliska przy dużym nachyleniu. Miejsca na manewrowanie zestawem jest wystarczająco, choć wymaga pewnej wprawy. Slip przystosowany jest do wodowania mniejszych i średnich łodzi, o masie do 2 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9411, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Umiarkowane', NULL, 1.2, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9412, 'Slip betonowy - Ryn', 'slip-betonowy-ryn-ryn-9412', 'SLIP', 53.9302961, 21.5289736, 'Warmińsko-Mazurskie', 'Ryn', 'Dojazd do slipu jest dogodny, prowadzi bezpośrednio z drogi wojewódzkiej, z dobrym oznakowaniem. Nawierzchnia slipu to solidny beton, zapewniający stabilność i bezpieczeństwo podczas wodowania. Dostępny jest duży plac manewrowy, umożliwiający swobodne operowanie nawet długimi zestawami. Slip zaprojektowano do wodowania jednostek o masie do 3,5 tony, w tym jachtów i motorówek.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9412, 'Czynny', 'Dla klientów', 'W cenie usługi', 'Całodobowo', 'Betonowy', 'Umiarkowane', NULL, 2, 'Na terenie obiektu', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9413, 'Slip piaszczysty - Rzepowskie', 'slip-piaszczysty-rzepowskie-rzepowskie-9413', 'SLIP', 49.9471747, 19.2751875, 'Małopolskie', 'Rzepowskie', 'Dojazd do slipu jest możliwy drogą polną, która może być trudna do pokonania po opadach deszczu. Nawierzchnia slipu jest piaszczysta, co wymaga ostrożności i napędu 4x4 przy cięższych jednostkach. Miejsca na manewrowanie jest niewiele, co wymaga precyzji i doświadczenia kierowcy. Slip przeznaczony jest głównie do wodowania kajaków, pontonów i małych łodzi wiosłowych, do 0.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9413, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Piaszczysty', 'Łagodne', NULL, 0.8, 'Brak', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9414, 'Slip z płyt betonowych - Piękna Góra', 'slip-z-plyt-betonowych-piekna-gora-piekna-gora-9414', 'SLIP', 54.0433456, 21.7388082, 'Warmińsko-Mazurskie', 'Piękna Góra', 'Dojazd do slipu jest bardzo dobry, drogą utwardzoną, z łatwym dostępem do parkingu. Nawierzchnia slipu składa się z solidnych płyt betonowych, zapewniających doskonałą przyczepność w każdych warunkach. Obiekt dysponuje obszernym placem manewrowym, umożliwiającym swobodne operowanie dużymi zestawami. Slip jest przystosowany do wodowania jednostek o masie do 5 ton, w tym dużych jachtów i motorówek.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9414, 'Czynny', 'Prywatny', 'Płatny', 'Całodobowo', 'Płyty betonowe', 'Strome', NULL, 2.5, 'Na terenie obiektu', TRUE, NULL, 'Dużo miejsca', NULL);
