INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9420, 'Slip Goczałkowicki - Przystań Zachodnia', 'slip-goczalkowicki-przystan-zachodnia-goczalkowice-zdroj-9420', 'SLIP', 49.9396128, 18.8265194, 'Śląskie', 'Goczałkowice-Zdrój', 'Dojazd do slipu odbywa się drogą utwardzoną, z ostatnim odcinkiem szutrowym. Nawierzchnia slipu wykonana jest z solidnych płyt betonowych, dobrze utrzymanych. Dostępne jest ograniczone miejsce na zestaw, co wymaga precyzji podczas manewrowania. Nośność slipu szacowana jest na pojazdy i jednostki do 3.5 tony.', NULL);
