INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9421, 'Slip Wodny - Goczałkowice-Zdrój Centrum', 'slip-wodny-goczalkowice-zdroj-centrum-goczalkowice-zdroj-9421', 'SLIP', 49.9395398, 18.8250332, 'Śląskie', 'Goczałkowice-Zdrój', 'Dojazd do obiektu jest łatwy, prowadzi asfaltową drogą gminną. Nawierzchnia slipu jest betonowa, w bardzo dobrym stanie technicznym i regularnie konserwowana. Na terenie obiektu dostępny jest dedykowany parking dla przyczep. Nośność slipu pozwala na bezpieczne wodowanie jednostek o masie do 5 ton.', NULL);
