INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9440, 'Slip betonowy - Broczyna', 'slip-betonowy-broczyna-broczyna-9440', 'SLIP', 54.1559437, 16.9756472, 'Zachodniopomorskie', 'Broczyna', 'Do slipu prowadzi utwardzona droga dojazdowa, zapewniająca łatwy dostęp. Nawierzchnia slipu wykonana jest z solidnego betonu, gwarantującego stabilność. Dostępne jest dużo miejsca do manewrowania zestawem z przyczepą. Obiekt charakteryzuje się wysoką nośnością, odpowiednią dla większości jednostek.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9440, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Betonowy', 'Łagodne', NULL, 1.8, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9441, 'Slip nad jeziorem - Kawka', 'slip-nad-jeziorem-kawka-kawka-9441', 'SLIP', 54.1900224, 16.8922587, 'Zachodniopomorskie', 'Kawka', 'Dojazd do slipu jest możliwy drogą gruntową, wymagającą ostrożności. Nawierzchnia składa się z wytrzymałych płyt betonowych, zapewniających dobrą przyczepność. Miejsce na zestaw z przyczepą jest ograniczone i wymaga wprawy w manewrowaniu. Nośność slipu jest wystarczająca dla średnich jednostek pływających.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9441, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.2, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9442, 'Slip miejski - Bydgoszcz', 'slip-miejski-bydgoszcz-bydgoszcz-9442', 'SLIP', 53.1205082, 18.0280751, 'Kujawsko-Pomorskie', 'Bydgoszcz', 'Slip położony jest w łatwo dostępnej lokalizacji miejskiej, z dobrym dojazdem asfaltowym. Nawierzchnia slipu jest asfaltowa, co zapewnia komfortowe użytkowanie. Ze względu na miejskie otoczenie, przestrzeń do manewrowania zestawem jest wąska. Obiekt charakteryzuje się wysoką nośnością, przystosowaną do intensywnego użytkowania.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9442, 'Czynny', 'Dla klientów', 'Płatny', 'Całodobowo', 'Asfaltowy', 'Łagodne', NULL, 2, 'Na terenie obiektu', TRUE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9443, 'Slip rzeczny - Siadło Dolne', 'slip-rzeczny-siadlo-dolne-siadlo-dolne-9443', 'SLIP', 53.3457502, 14.4973267, 'Zachodniopomorskie', 'Siadło Dolne', 'Dojazd do slipu jest utrudniony, prowadzi przez nieutwardzoną drogę. Nawierzchnia slipu jest żwirowa, co może stanowić wyzwanie dla niektórych pojazdów. Brak jest dedykowanego miejsca do manewrowania zestawem z przyczepą. Ze względu na remont, nośność obiektu jest tymczasowo ograniczona.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9443, 'W remoncie', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Strome', NULL, 1, 'Brak', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9444, 'Slip nadmorski - Gleźnowo', 'slip-nadmorski-gleznowo-gleznowo-9444', 'SLIP', 54.3426409, 16.3119864, 'Zachodniopomorskie', 'Gleźnowo', 'Dojazd do slipu jest komfortowy, prowadzi utwardzoną drogą. Nawierzchnia slipu jest piaszczysta, co wymaga odpowiedniej techniki. Dostępne jest dużo miejsca do manewrowania zestawem z przyczepą. Obiekt charakteryzuje się dobrą nośnością, odpowiednią dla większości jednostek rekreacyjnych.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9444, 'Czynny', 'Tylko dla członków klubu', 'W cenie usługi', 'Całodobowo', 'Piaszczysty', 'Umiarkowane', NULL, 1.5, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9445, 'Slip betonowy - Gleźnowo', 'slip-betonowy-gleznowo-gleznowo-9445', 'SLIP', 54.3424864, 16.3210712, 'Zachodniopomorskie', 'Gleźnowo', 'Dojazd do slipu jest utwardzony, prowadzi bezpośrednio z drogi gminnej. Nawierzchnia slipu wykonana jest z płyt betonowych, zapewniając dobrą przyczepność. Dostępne jest obszerne miejsce do manewrowania zestawem z przyczepą. Nośność konstrukcji pozwala na wodowanie jednostek o masie do 3 ton.', NULL);
