INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9481, 'Slip żwirowy - Góra Puławska', 'slip-zwirowy-gora-pulawska-gora-pulawska-9481', 'SLIP', 51.4119201, 21.9417545, 'Lubelskie', 'Góra Puławska', 'Dojazd do slipu prowadzi drogą gruntową, wymagającą ostrożności. Nawierzchnia żwirowa jest stabilna, ale może być śliska po deszczu. Miejsce na zestaw jest ograniczone, co wymaga precyzyjnego manewrowania. Slip przystosowany jest do wodowania mniejszych jednostek o masie do 1.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9481, 'Czynny', 'Dla klientów', 'W cenie usługi', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1.2, 'Na terenie obiektu', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9482, 'Slip portowy - Dźwirzyno', 'slip-portowy-dzwirzyno-dzwirzyno-9482', 'SLIP', 54.1493233, 15.3985951, 'Zachodniopomorskie', 'Dźwirzyno', 'Dojazd do slipu jest asfaltowy, dobrze oznakowany. Nawierzchnia betonowa zapewnia doskonałą przyczepność, nawet przy stromym nachyleniu. Ze względu na ruch portowy, miejsce na manewrowanie zestawem jest ograniczone i wymaga wprawy. Slip jest przystosowany do wodowania jednostek o masie do 4 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9482, 'Czynny', 'Publiczny', 'Płatny', 'Całodobowo', 'Betonowy', 'Strome', NULL, 2, 'Ograniczony', TRUE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9483, 'Slip rekreacyjny - Przystajnia', 'slip-rekreacyjny-przystajnia-przystajnia-9483', 'SLIP', 51.5846461, 18.1805573, 'Wielkopolskie', 'Przystajnia', 'Dojazd do slipu prowadzi przez teren prywatny, wymagane jest uzgodnienie. Nawierzchnia trawiasta jest odpowiednia dla lekkich łodzi, ale może być grząska po opadach. Dostępne jest dużo miejsca na swobodne manewrowanie zestawem. Slip przeznaczony jest dla lekkich jednostek o masie do 0.8 tony.', NULL);
