INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9485, 'Slip betonowy - Siadło Dolne', 'slip-betonowy-siadlo-dolne-siadlo-dolne-9485', 'SLIP', 53.3646153, 14.5124681, 'Zachodniopomorskie', 'Siadło Dolne', 'Dojazd do slipu odbywa się drogą utwardzoną, z ostatnim odcinkiem szutrowym. Nawierzchnia slipu wykonana jest z solidnych płyt betonowych, zapewniających dobrą przyczepność. Dostępne jest dużo miejsca na manewrowanie zestawem z przyczepą. Nośność konstrukcji slipu pozwala na bezpieczne wodowanie jednostek o masie do 3 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9485, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.8, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9486, 'Slip miejski - Mieszkowice', 'slip-miejski-mieszkowice-mieszkowice-9486', 'SLIP', 52.7841634, 14.49736, 'Zachodniopomorskie', 'Mieszkowice', 'Dojazd do slipu jest bezpośredni z drogi wojewódzkiej i jest dobrze oznakowany. Nawierzchnia slipu jest asfaltowa, utrzymana w dobrym stanie technicznym. Miejsce na manewrowanie zestawem jest ograniczone i wymaga precyzji. Nośność slipu pozwala na wodowanie jednostek o masie do 2 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9486, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Asfaltowy', 'Łagodne', NULL, 1.5, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9487, 'Slip żwirowy - Zborówko', 'slip-zwirowy-zborowko-zborowko-9487', 'SLIP', 52.3757716, 16.6245952, 'Wielkopolskie', 'Zborówko', 'Dojazd do slipu prowadzi drogą polną, w deszczowe dni może być wymagany napęd 4x4. Nawierzchnia slipu to utwardzony żwir z domieszką piasku, zapewniający stabilność. Dostępne jest wystarczająco miejsca na manewrowanie zestawem. Nośność slipu jest odpowiednia dla jednostek o masie do 1.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9487, 'W remoncie', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Umiarkowane', NULL, 1.2, 'Dostępny', FALSE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9488, 'Slip portowy - Trzebież', 'slip-portowy-trzebiez-trzebiez-9488', 'SLIP', 53.6621066, 14.5145706, 'Zachodniopomorskie', 'Trzebież', 'Dojazd do slipu odbywa się drogą asfaltową, bezpośrednio do terenu portu. Nawierzchnia slipu to solidny beton, regularnie konserwowany i w bardzo dobrym stanie. Dostępne jest dużo miejsca na manewrowanie zestawem, z wydzielonym placem. Nośność slipu pozwala na wodowanie jednostek o masie do 5 ton.', NULL);
