INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9508, 'Slip rzeczny - Płock', 'slip-rzeczny-plock-plock-9508', 'SLIP', 52.5414379, 19.6850328, 'Mazowieckie', 'Płock', 'Dojazd do slipu jest asfaltowy, zlokalizowany w pobliżu miejskiej przystani. Nawierzchnia składa się z dużych, stabilnych płyt betonowych, dobrze utrzymanych. Miejsce na zestaw z przyczepą jest ograniczone, wymaga precyzyjnego manewrowania. Slip przystosowany jest do wodowania jednostek o wadze do 2,5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9508, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Łagodne', NULL, 1.8, 'Ograniczony', TRUE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9509, 'Slip jeziorny - Głęboczek Północ', 'slip-jeziorny-gleboczek-polnoc-gleboczek-9509', 'SLIP', 53.5760098, 16.0747694, 'Zachodniopomorskie', 'Głęboczek', 'Dojazd do slipu prowadzi polną drogą, która może być trudna po opadach deszczu. Nawierzchnia jest żwirowa, co wymaga ostrożności podczas wodowania. Brak wydzielonego miejsca na zestaw z przyczepą, co utrudnia operacje. Nośność slipu jest szacowana na około 1,5 tony, głównie dla mniejszych jednostek.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9509, 'W remoncie', 'Prywatny', 'Płatny', 'Całodobowo', 'Żwirowy', 'Strome', NULL, 1.2, 'Brak', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9510, 'Slip rekreacyjny - Głęboczek Południe', 'slip-rekreacyjny-gleboczek-poludnie-gleboczek-9510', 'SLIP', 53.5754765, 16.0748257, 'Zachodniopomorskie', 'Głęboczek', 'Dojazd do slipu jest dobrze utrzymany, prowadzi przez teren ośrodka wypoczynkowego. Nawierzchnia piaszczysta, utwardzona, zapewnia płynne wodowanie lekkich jednostek. Dostępne jest obszerne miejsce na zestaw z przyczepą, w ramach parkingu obiektu. Slip przeznaczony jest dla łodzi o masie do 1 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9510, 'Czynny', 'Dla klientów', 'W cenie usługi', 'Całodobowo', 'Piaszczysty', 'Łagodne', NULL, 1, 'Na terenie obiektu', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9511, 'Slip gminny - Brzeżno', 'slip-gminny-brzezno-gmina-brzezno-9511', 'SLIP', 53.6697776, 15.9266319, 'Zachodniopomorskie', 'gmina Brzeżno', 'Dojazd do slipu jest gruntowy, wymaga ostrożności zwłaszcza po deszczu. Nawierzchnia trawiasta, co ogranicza jego użyteczność do małych, lekkich jednostek. Miejsce na zestaw z przyczepą jest bardzo ograniczone, co utrudnia manewrowanie. Slip nie jest przeznaczony do wodowania ciężkich łodzi, maksymalna nośność to około 700 kg.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9511, 'Nieczynny', 'Tylko dla członków klubu', 'Płatny', 'Całodobowo', 'Trawa', 'Umiarkowane', NULL, 0.8, 'Ograniczony', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9519, 'Slip Portowy - Zielonczyn', 'slip-portowy-zielonczyn-zielonczyn-9519', 'SLIP', 53.6985809, 14.6757194, 'Zachodniopomorskie', 'Zielonczyn', 'Dojazd do slipu drogą utwardzoną, łatwy i dobrze oznakowany. Nawierzchnia slipu wykonana jest z solidnych płyt betonowych, zapewniających dobrą przyczepność. Na miejscu dostępny jest obszerny parking dla zestawów z przyczepami. Nośność konstrukcji pozwala na wodowanie jednostek o masie do 3 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9519, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.8, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9520, 'Slip Miejski - Szczecin', 'slip-miejski-szczecin-szczecin-9520', 'SLIP', 53.3975971, 14.6318944, 'Zachodniopomorskie', 'Szczecin', 'Dojazd do slipu prowadzi przez miejskie ulice, co może być utrudnione w godzinach szczytu. Nawierzchnia jest betonowa, w dobrym stanie, z antypoślizgową fakturą. Dostępne jest ograniczone miejsce parkingowe dla przyczep wzdłuż ulicy. Slip przystosowany jest do wodowania jednostek o wadze do 2,5 tony.', NULL);
