INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9521, 'Slip Leśny - Stary Młyn', 'slip-lesny-stary-mlyn-stary-mlyn-9521', 'SLIP', 53.7546451, 19.1367463, 'Pomorskie', 'Stary Młyn', 'Dojazd do slipu drogą gruntową, wymagającą ostrożności, szczególnie po opadach. Nawierzchnia żwirowa, obecnie w trakcie remontu, co wpływa na jej stabilność. Parking dla przyczep dostępny jest wyłącznie na terenie przyległego ośrodka. Maksymalna nośność slipu szacowana jest na 1,5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9521, 'W remoncie', 'Prywatny', 'W cenie usługi', 'Całodobowo', 'Żwirowy', 'Strome', NULL, 1, 'Na terenie obiektu', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9522, 'Slip Przybrzeżny - Bukowo Morskie', 'slip-przybrzezny-bukowo-morskie-bukowo-morskie-9522', 'SLIP', 54.3557639, 16.3396054, 'Zachodniopomorskie', 'Bukowo Morskie', 'Dojazd do slipu utwardzoną drogą, łatwy i komfortowy dla większości pojazdów. Nawierzchnia piaszczysta, regularnie konserwowana, idealna do lekkich jednostek. Dostępny jest duży, wydzielony parking dla przyczep w pobliżu slipu. Slip przeznaczony jest do wodowania łodzi o masie do 1 tony.', NULL);
