INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9523, 'Slip Jeziorny - Kanice', 'slip-jeziorny-kanice-kanice-9523', 'SLIP', 53.4733409, 15.5967294, 'Zachodniopomorskie', 'Kanice', 'Dojazd do slipu wąską, nieutwardzoną drogą, wymagającą ostrożności i pojazdu 4x4. Nawierzchnia trawiasta, naturalna, co ogranicza jej nośność i stabilność. Brak dedykowanego parkingu dla przyczep w bezpośrednim sąsiedztwie. Slip jest odpowiedni dla małych łodzi i pontonów o masie do 500 kg.', NULL);
