INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9525, 'Slip żwirowy - Wojkowice Kościelne', 'slip-zwirowy-wojkowice-koscielne-wojkowice-koscielne-9525', 'SLIP', 50.406453, 19.2071698, 'Śląskie', 'Wojkowice Kościelne', 'Dojazd do slipu drogą gruntową, może być utrudniony po intensywnych opadach. Nawierzchnia żwirowa, wymaga ostrożności przy wodowaniu cięższych łodzi. Miejsce na zestaw z przyczepą jest ograniczone, zaleca się wcześniejsze przygotowanie. Nośność slipu jest odpowiednia dla małych i średnich jednostek, do 1.5 tony.', NULL);
