INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9526, 'Slip z płyt betonowych - Prostynia (Północny)', 'slip-z-plyt-betonowych-prostynia-polnocny-prostynia-9526', 'SLIP', 53.3133523, 15.7727602, 'Zachodniopomorskie', 'Prostynia', 'Dojazd asfaltową drogą lokalną, bardzo dobry i bezproblemowy. Nawierzchnia slipu wykonana z solidnych, antypoślizgowych płyt betonowych. Dostępne jest obszerne miejsce do manewrowania i parkowania zestawu z przyczepą. Slip przystosowany do wodowania jednostek o masie do 4 ton.', NULL);
