INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9535, 'Prywatny slip w Zaniemyślu', 'prywatny-slip-w-zaniemyslu-zaniemysl-9535', 'SLIP', 52.1505605, 17.163007, 'Wielkopolskie', 'Zaniemyśl', 'Dojazd do slipu prowadzi przez teren prywatnej posesji, drogą gruntową. Nawierzchnia slipu to utwardzony żwir, wymagający ostrożności przy wodowaniu. Miejsce na zestaw jest dostępne na terenie obiektu, ale wymaga uzgodnienia. Nośność slipu jest wystarczająca dla łodzi do 1,8 tony.', NULL);
