INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9536, 'Slip gminny - Chmieleńskie Chrósty', 'slip-gminny-chmielenskie-chrosty-chmielenskie-chrosty-9536', 'SLIP', 54.316733, 18.083783, 'Pomorskie', 'Chmieleńskie Chrósty', 'Dojazd do slipu asfaltowy, bezpośrednio z drogi wojewódzkiej. Nawierzchnia slipu jest betonowa, w dobrym stanie technicznym, zapewniająca stabilność. Duże, utwardzone miejsce na manewrowanie zestawem oraz parking dla przyczep. Konstrukcja slipu przystosowana do wodowania jednostek do 3,5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9536, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Betonowy', 'Umiarkowane', NULL, 1.8, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9537, 'Slip dla wędkarzy - Korne', 'slip-dla-wedkarzy-korne-korne-9537', 'SLIP', 54.1382346, 17.8608647, 'Pomorskie', 'Korne', 'Dojazd do slipu drogą polną, może być utrudniony po opadach deszczu. Nawierzchnia slipu to ubita trawa z elementami piasku, odpowiednia dla mniejszych jednostek. Miejsce na zestaw jest ograniczone, wymaga precyzji przy manewrowaniu. Nośność slipu szacowana na maksymalnie 1,0 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9537, 'W remoncie', 'Dla klientów', 'W cenie usługi', 'Całodobowo', 'Trawa', 'Łagodne', NULL, 0.8, 'Brak', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9538, 'Slip rekreacyjny - Glewnik', 'slip-rekreacyjny-glewnik-glewnik-9538', 'SLIP', 54.2161381, 17.0604298, 'Pomorskie', 'Glewnik', 'Dojazd do slipu drogą szutrową, dobrze utrzymaną. Nawierzchnia slipu wykonana z asfaltu, zapewniająca dobrą przyczepność. Dostępne jest wystarczające miejsce na manewrowanie zestawem, z wydzielonym parkingiem. Slip przystosowany do wodowania jednostek o wadze do 2,0 ton.', NULL);
