INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9539, 'Slip na rzece Barycz - Nowe Grodzisko', 'slip-na-rzece-barycz-nowe-grodzisko-nowe-grodzisko-9539', 'SLIP', 51.5527919, 17.3601163, 'Wielkopolskie', 'Nowe Grodzisko', 'Dojazd do slipu drogą utwardzoną, łatwy dla większości pojazdów. Nawierzchnia slipu wykonana z solidnych płyt betonowych, zapewniających dobrą przyczepność. Dostępne jest obszerne miejsce do manewrowania zestawem z przyczepą. Nośność konstrukcji pozwala na wodowanie jednostek o masie do 3 ton.', NULL);
