INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9540, 'Slip nad Odrą - Rudawica', 'slip-nad-odra-rudawica-rudawica-9540', 'SLIP', 51.5447944, 15.3888767, 'Lubuskie', 'Rudawica', 'Dojazd do slipu drogą polną, zalecany napęd 4x4 w deszczowe dni. Nawierzchnia żwirowa, stabilna, lecz wymaga ostrożności przy wodowaniu cięższych łodzi. Miejsce do manewrowania zestawem jest ograniczone, co wymaga pewnej wprawy. Slip przystosowany do wodowania jednostek o masie do 2 ton.', NULL);
