INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9541, 'Slip nad jeziorem Wicko - Biesowiczki Północ', 'slip-nad-jeziorem-wicko-biesowiczki-polnoc-biesowiczki-9541', 'SLIP', 54.1652294, 16.9043462, 'Zachodniopomorskie', 'Biesowiczki', 'Dojazd do slipu drogą asfaltową, ostatni odcinek prywatny. Nawierzchnia betonowa, miejscami z ubytkami, obecnie w trakcie remontu. Ze względu na strome nachylenie i wąskie miejsce, manewrowanie wymaga dużej precyzji. Nośność slipu szacowana na 4 tony, jednak zalecana ostrożność do czasu zakończenia prac.', NULL);
