INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9555, 'Slip z płyt betonowych - Zaborze', 'slip-z-plyt-betonowych-zaborze-zaborze-9555', 'SLIP', 53.1649513, 14.5499118, 'Zachodniopomorskie', 'Zaborze', 'Dojazd do slipu odbywa się drogą gruntową, która w sezonie jest regularnie utwardzana. Nawierzchnia składa się z solidnych płyt betonowych, zapewniających dobrą przyczepność. Miejsca na zestaw z przyczepą jest wystarczająco, choć wymaga ostrożności przy manewrowaniu. Slip jest przeznaczony dla jednostek o maksymalnej masie do 2 ton.', NULL);
