INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9556, 'Slip żwirowy - Świerże Górne', 'slip-zwirowy-swierze-gorne-swierze-gorne-9556', 'SLIP', 51.66049, 21.4841505, 'Mazowieckie', 'Świerże Górne', 'Dojazd do slipu jest możliwy drogą polną, która może być wymagająca po opadach deszczu. Nawierzchnia slipu to dobrze ubity żwir, odpowiedni dla mniejszych jednostek. Miejsce na manewrowanie zestawem jest ograniczone, zaleca się ostrożność. Slip jest przeznaczony głównie dla łodzi o masie do 1 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9556, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Umiarkowane', NULL, 0.9, 'Brak', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9557, 'Slip drewniany - Lublin', 'slip-drewniany-lublin-lublin-9557', 'SLIP', 51.2375049, 22.5583204, 'Lubelskie', 'Lublin', 'Dojazd do slipu jest wygodny, prowadzi asfaltową drogą miejską. Nawierzchnia slipu wykonana jest z solidnych, impregnowanych desek, zapewniających bezpieczne wodowanie. Dostępne jest ograniczone miejsce do manewrowania i parkowania przyczep w pobliżu. Slip jest przeznaczony dla jednostek o masie do 1.5 tony.', NULL);
