INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9603, 'Slip portowy - Wilkasy (Jezioro Niegocin)', 'slip-portowy-wilkasy-jezioro-niegocin-wilkasy-9603', 'SLIP', 54.0086139, 21.7381092, 'Warmińsko-Mazurskie', 'Wilkasy', 'Dojazd do slipu jest asfaltowy, bardzo dobrze utrzymany, w obrębie portu. Nawierzchnia slipu jest betonowa, solidna i antypoślizgowa. Miejsce na manewrowanie zestawem jest ograniczone, ale dobrze zorganizowane. Slip charakteryzuje się wysoką nośnością, do 4 ton, idealny dla większych jednostek.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9603, 'Czynny', 'Dla klientów', 'Płatny', 'Całodobowo', 'Betonowy', 'Strome', NULL, 1.8, 'Na terenie obiektu', TRUE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9604, 'Slip rzeczny - Reńska Wieś', 'slip-rzeczny-renska-wies-renska-wies-9604', 'SLIP', 50.3209189, 18.1402614, 'Opolskie', 'Reńska Wieś', 'Dojazd do slipu prowadzi drogą utwardzoną, lecz wąską. Nawierzchnia wykonana jest z solidnych płyt betonowych, zapewniających dobrą przyczepność. Miejsce na zestaw jest ograniczone, co wymaga precyzji manewrowania. Nośność konstrukcji pozwala na wodowanie jednostek do 2,5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9604, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.2, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9605, 'Slip rekreacyjny - Dębowa', 'slip-rekreacyjny-debowa-debowa-9605', 'SLIP', 50.3155916, 18.1495946, 'Opolskie', 'Dębowa', 'Dojazd do slipu odbywa się polną drogą, która może być wymagająca po opadach. Nawierzchnia żwirowa zapewnia stabilność, choć może być śliska. Dostępne jest obszerne miejsce na zestaw, ułatwiające manewry. Slip przystosowany jest do wodowania łodzi o masie do 1,5 tony.', NULL);
