INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9624, 'Slip żwirowy - Czosnowo', 'slip-zwirowy-czosnowo-czosnowo-9624', 'SLIP', 53.8065536, 17.3530514, 'Pomorskie', 'Czosnowo', 'Dojazd do slipu drogą utwardzoną, ostatnie 50 metrów to droga gruntowa. Nawierzchnia slipu wykonana jest ze stabilizowanego żwiru, co zapewnia dobrą przyczepność. Dostępne jest obszerne miejsce do manewrowania zestawem z przyczepą. Nośność konstrukcji pozwala na wodowanie jednostek o masie do 2,5 tony.', NULL);
