INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9625, 'Slip miejski - Warszawa (Wał Miedzeszyński)', 'slip-miejski-warszawa-wal-miedzeszynski-warszawa-9625', 'SLIP', 52.193769, 21.1033035, 'Mazowieckie', 'Warszawa', 'Dojazd do slipu jest asfaltowy, zlokalizowany wzdłuż głównej drogi. Nawierzchnia slipu to solidny beton, zapewniający stabilność podczas wodowania. Miejsce na zestaw z przyczepą jest ograniczone, wymaga precyzyjnego manewrowania. Slip przystosowany jest do wodowania jednostek o masie do 3 ton.', NULL);
