INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9626, 'Slip portowy - Ruciane-Nida', 'slip-portowy-ruciane-nida-ruciane-nida-9626', 'SLIP', 53.6490138, 21.570093, 'Warmińsko-Mazurskie', 'Ruciane-Nida', 'Dojazd do slipu prowadzi przez teren portu, drogą utwardzoną. Nawierzchnia slipu wykonana jest z solidnych płyt betonowych, wzmocnionych metalowymi elementami. Miejsce na manewrowanie zestawem jest wąskie, co wymaga doświadczenia. Nośność slipu pozwala na wodowanie jednostek o masie do 4 ton.', NULL);
