INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9659, 'Slip Portowy - Giżycko', 'slip-portowy-gizycko-gizycko-9659', 'SLIP', 54.0311697, 21.7740474, 'Warmińsko-Mazurskie', 'Giżycko', 'Dojazd do slipu jest łatwy, prowadzi drogą asfaltową bezpośrednio z głównej ulicy portowej. Nawierzchnia slipu wykonana jest z solidnych płyt betonowych, wzmocnionych metalowymi elementami, co zapewnia bardzo dobrą przyczepność i trwałość. W pobliżu dostępny jest duży plac manewrowy, umożliwiający swobodne operowanie zestawami z przyczepą. Obiekt przystosowany jest do wodowania jednostek o masie do 5 ton, z głębokością końcową 1.8 metra.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9659, 'Czynny', 'Dla klientów', 'W cenie usługi', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.8, 'Na terenie obiektu', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9660, 'Slip Jachtowy - Giżycko', 'slip-jachtowy-gizycko-gizycko-9660', 'SLIP', 54.0311595, 21.7741475, 'Warmińsko-Mazurskie', 'Giżycko', 'Dojazd do slipu jest umiarkowanie łatwy, drogą utwardzoną, wymagającą uwagi przy większych zestawach. Nawierzchnia slipu to płyty betonowe z widocznymi elementami wzmocnień, oferujące dostateczną przyczepność. W pobliżu dostępny jest ograniczony plac manewrowy, co wymaga wprawy przy manewrowaniu zestawem z przyczepą. Slip przeznaczony jest dla jednostek o masie do 3 ton, z głębokością końcową wynoszącą 1.5 metra.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9660, 'Czynny', 'Dla klientów', 'W cenie usługi', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.5, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9661, 'Slip nad Zalewem Rybnickim', 'slip-nad-zalewem-rybnickim-rybnik-9661', 'SLIP', 50.169186, 18.4780064, 'Śląskie', 'Rybnik', 'Dojazd do slipu jest możliwy drogą szutrową, która może być nierówna w niektórych miejscach. Nawierzchnia slipu jest żwirowa, co zapewnia naturalną przyczepność, ale może wymagać napędu 4x4 przy cięższych jednostkach. W okolicy slipu dostępny jest duży, otwarty teren, oferujący swobodne miejsce na manewrowanie zestawem z przyczepą. Obiekt nadaje się do wodowania mniejszych łodzi i skuterów wodnych, z głębokością końcową około 1.0 metra.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9661, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1, 'Brak', FALSE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9662, 'Slip Prywatny - Kraków', 'slip-prywatny-krakow-krakow-9662', 'SLIP', 50.0411258, 20.0991654, 'Małopolskie', 'Kraków', 'Dojazd do slipu jest łatwy, prowadzi prywatną drogą asfaltową, dobrze utrzymaną. Nawierzchnia slipu jest betonowa, w bardzo dobrym stanie, zapewniająca doskonałą przyczepność w każdych warunkach. Dostępny jest ograniczony plac manewrowy na terenie obiektu, co wymaga precyzji przy operowaniu zestawem z przyczepą. Slip przystosowany jest do wodowania jednostek o masie do 4 ton, z głębokością końcową 1.2 metra.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9662, 'Czynny', 'Prywatny', 'Płatny', 'Całodobowo', 'Betonowy', 'Umiarkowane', NULL, 1.2, 'Na terenie obiektu', TRUE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9663, 'Slip Rzeczny - Tomaszów Mazowiecki', 'slip-rzeczny-tomaszow-mazowiecki-tomaszow-mazowiecki-9663', 'SLIP', 51.5188441, 20.0324724, 'Łódzkie', 'Tomaszów Mazowiecki', 'Dojazd do slipu jest utrudniony, prowadzi nieutwardzoną drogą polną, która może być błotnista po opadach. Nawierzchnia slipu jest piaszczysta, co zapewnia umiarkowaną przyczepność i jest podatna na erozję. W pobliżu slipu dostępny jest ograniczony teren do manewrowania, wymagający ostrożności i doświadczenia. Obiekt przeznaczony jest dla lekkich łodzi i kajaków, z głębokością końcową około 0.8 metra.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9663, 'W remoncie', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Piaszczysty', 'Łagodne', NULL, 0.8, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9664, 'Slip betonowy - Lelów', 'slip-betonowy-lelow-lelow-9664', 'SLIP', 50.6849822, 19.6209647, 'Śląskie', 'Lelów', 'Dojazd do slipu jest utwardzony, prowadzi bezpośrednio z drogi gminnej. Nawierzchnia slipu wykonana jest z solidnych płyt betonowych, zapewniających dobrą przyczepność. Na placu manewrowym dostępna jest wystarczająca przestrzeń dla zestawu z przyczepą. Obiekt przystosowany jest do wodowania jednostek o masie do 3 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9664, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.8, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9665, 'Slip żwirowy - Chodzież (Jezioro Chodzieskie)', 'slip-zwirowy-chodziez-jezioro-chodzieskie-chodziez-9665', 'SLIP', 52.9892757, 16.9243596, 'Wielkopolskie', 'Chodzież', 'Dojazd do slipu prowadzi przez teren prywatny, wymagane jest wcześniejsze uzgodnienie. Nawierzchnia jest żwirowa, co wymaga ostrożności przy wodowaniu cięższych jednostek. Miejsce na zestaw z przyczepą jest ograniczone, zaleca się precyzyjne manewrowanie. Slip przeznaczony jest dla lekkich łodzi i skuterów wodnych, nośność do 1.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9665, 'Czynny', 'Prywatny', 'Płatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1.2, 'Na terenie obiektu', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9666, 'Slip portowy - Pyskowice', 'slip-portowy-pyskowice-pyskowice-9666', 'SLIP', 50.3814822, 18.5575483, 'Śląskie', 'Pyskowice', 'Dojazd do slipu jest asfaltowy, dobrze oznakowany i łatwy do znalezienia. Nawierzchnia slipu to solidny beton, zapewniający stabilność i bezpieczeństwo. Dostępne jest obszerne miejsce do manewrowania zestawem z przyczepą. Slip przystosowany jest do wodowania jednostek o masie do 5 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9666, 'Czynny', 'Dla klientów', 'W cenie usługi', 'Całodobowo', 'Betonowy', 'Umiarkowane', NULL, 2, 'Na terenie obiektu', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9667, 'Slip plażowy - Taciszów', 'slip-plazowy-taciszow-taciszow-9667', 'SLIP', 50.3838626, 18.5532554, 'Śląskie', 'Taciszów', 'Dojazd do slipu prowadzi polną drogą, która może być trudna po opadach deszczu. Nawierzchnia jest piaszczysta, co wymaga napędu 4x4 lub dużej ostrożności. Miejsce na zestaw z przyczepą jest ograniczone, zaleca się parkowanie poza bezpośrednim obszarem slipu. Slip przeznaczony jest głównie dla małych łodzi i kajaków, nośność do 1 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9667, 'Nieczynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Piaszczysty', 'Łagodne', NULL, 1, 'Brak', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9668, 'Slip klubowy - Smolęcin', 'slip-klubowy-smolecin-smolecin-9668', 'SLIP', 53.8736928, 15.2319748, 'Zachodniopomorskie', 'Smolęcin', 'Dojazd do slipu jest utwardzony, prowadzi przez teren zamknięty klubu żeglarskiego. Nawierzchnia slipu jest asfaltowa, w dobrym stanie technicznym. Dostępne jest ograniczone miejsce na zestaw z przyczepą, ale wystarczające dla członków klubu. Slip jest przeznaczony dla jednostek o masie do 2.5 tony.', NULL);
