INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9669, 'Slip żwirowy - Dąbrówka', 'slip-zwirowy-dabrowka-dabrowka-9669', 'SLIP', 49.8177474, 19.5773186, 'Małopolskie', 'Dąbrówka', 'Dojazd do slipu jest możliwy drogą utwardzoną, jednak ostatni odcinek wymaga uwagi. Nawierzchnia slipu jest żwirowa, co zapewnia dobrą przyczepność dla pojazdów 4x4. Miejsce na zestaw jest ograniczone, co może utrudniać manewrowanie większymi przyczepami. Slip jest przystosowany do wodowania jednostek o masie do 1500 kg.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9669, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
