INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9684, 'Slip betonowy - Wdzydze Kiszewskie', 'slip-betonowy-wdzydze-kiszewskie-wdzydze-9684', 'SLIP', 54.0152621, 17.921427, 'Pomorskie', 'Wdzydze', 'Dojazd do slipu drogą utwardzoną, ostatni odcinek szutrowy. Nawierzchnia slipu wykonana z solidnych płyt betonowych, zapewniających dobrą przyczepność. Dostępne obszerne miejsce do manewrowania zestawem z przyczepą. Nośność konstrukcji przystosowana do jednostek o masie do 3 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9684, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Betonowy', 'Umiarkowane', NULL, 1.5, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9685, 'Slip miejski - Iława', 'slip-miejski-ilawa-ilawa-9685', 'SLIP', 53.5992047, 19.5536161, 'Warmińsko-Mazurskie', 'Iława', 'Obiekt położony w centrum miasta, z łatwym dojazdem asfaltową drogą. Nawierzchnia slipu to gładki beton, regularnie konserwowany. Na miejscu wyznaczono dedykowane miejsca parkingowe dla przyczep. Maksymalna nośność slipu wynosi 4 tony.', NULL);
