INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9686, 'Slip przy przystani - Zawory', 'slip-przy-przystani-zawory-zawory-9686', 'SLIP', 54.3108218, 18.1030841, 'Pomorskie', 'Zawory', 'Dojazd do slipu prowadzi wąską drogą gruntową, wymagającą ostrożności. Nawierzchnia składa się z płyt ażurowych, częściowo porośniętych trawą. Miejsce na zestaw jest ograniczone, co wymaga precyzyjnego manewrowania. Konstrukcja slipu jest przeznaczona dla jednostek do 2 ton.', NULL);
