INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9687, 'Slip rzeczny - Krępsko', 'slip-rzeczny-krepsko-krepsko-9687', 'SLIP', 53.2643702, 16.7691082, 'Wielkopolskie', 'Krępsko', 'Dojazd do slipu odbywa się polną drogą, która może być trudna po opadach. Nawierzchnia żwirowa, stabilna, ale wymaga uwagi przy wjeździe. Brak wydzielonego miejsca na parking dla przyczep w bezpośrednim sąsiedztwie. Slip przystosowany do wodowania małych łodzi o masie do 1,5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9687, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1, 'Brak', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9688, 'Slip klubowy - Czarne', 'slip-klubowy-czarne-czarne-9688', 'SLIP', 53.8367711, 18.2140763, 'Pomorskie', 'Czarne', 'Dojazd do obiektu drogą gruntową, dobrze utrzymaną przez klub. Nawierzchnia piaszczysta, utwardzona, z możliwością lekkiego zapadania się kół. Dostępne jest ograniczone miejsce do manewrowania zestawem. Nośność slipu szacuje się na około 1 tonę.', NULL);
