INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9689, 'Slip Portowy - Poznań Malta', 'slip-portowy-poznan-malta-poznan-9689', 'SLIP', 52.4441386, 16.8025363, 'Wielkopolskie', 'Poznań', 'Dojazd do slipu jest łatwy, prowadzi utwardzoną drogą. Nawierzchnia slipu wykonana jest z solidnego betonu, zapewniającego dobrą przyczepność. W pobliżu dostępny jest dedykowany parking na terenie obiektu dla zestawów samochodowych z przyczepą. Konstrukcja slipu zapewnia wysoką nośność, odpowiednią dla średnich i większych jednostek pływających.', NULL);
