INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9690, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1.2, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9691, 'Slip Rzeczny - Konin Warta', 'slip-rzeczny-konin-warta-konin-9691', 'SLIP', 52.3028691, 18.2625701, 'Wielkopolskie', 'Konin', 'Dojazd do slipu jest komfortowy, drogą asfaltową z łatwym manewrowaniem. Nawierzchnia slipu wykonana jest z solidnych płyt betonowych, zapewniających stabilność. W pobliżu dostępny jest przestronny parking na zestaw samochodowy z przyczepą. Konstrukcja slipu zapewnia wysoką nośność, odpowiednią dla różnorodnych jednostek pływających.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9691, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 2, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9692, 'Slip Prywatny - Poznań Strzeszynek', 'slip-prywatny-poznan-strzeszynek-poznan-9692', 'SLIP', 52.4416803, 16.7977771, 'Wielkopolskie', 'Poznań', 'Dojazd do slipu jest utwardzony, lecz wymaga precyzji ze względu na ograniczoną przestrzeń. Nawierzchnia slipu to solidny beton, zapewniający dobrą przyczepność nawet przy stromym nachyleniu. Parking dla zestawów samochodowych z przyczepą dostępny jest na terenie obiektu, jednak miejsce jest ograniczone. Konstrukcja slipu zapewnia wysoką nośność, przeznaczoną dla jednostek o średniej wielkości.', NULL);
