INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9725, 'Slip żwirowy - Grodzisko', 'slip-zwirowy-grodzisko-grodzisko-9725', 'SLIP', 49.9643967, 19.4519749, 'Małopolskie', 'Grodzisko', 'Dojazd do slipu odbywa się drogą gruntową, wymagającą ostrożności w deszczowe dni. Nawierzchnia slipu jest żwirowa, co może wymagać napędu 4x4 dla cięższych jednostek. Miejsce na zestaw jest ograniczone, co wymaga precyzyjnego manewrowania. Nośność slipu jest odpowiednia dla mniejszych łodzi i skuterów wodnych.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9725, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Umiarkowane', NULL, 1, 'Ograniczony', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9726, 'Slip płyty betonowe - Rościn', 'slip-plyty-betonowe-roscin-roscin-9726', 'SLIP', 53.2701177, 15.7738739, 'Zachodniopomorskie', 'Rościn', 'Dojazd do slipu jest dobrze utrzymany, z utwardzoną drogą dojazdową. Nawierzchnia składa się z solidnych płyt betonowych, zapewniających stabilność. Na terenie obiektu znajduje się wystarczająco dużo miejsca na manewrowanie zestawem. Slip przystosowany jest do wodowania jednostek o średniej i dużej masie.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9726, 'Czynny', 'Dla klientów', 'W cenie usługi', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.8, 'Na terenie obiektu', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9727, 'Slip piaszczysty - Samociążek', 'slip-piaszczysty-samociazek-samociazek-9727', 'SLIP', 53.2735083, 17.9756869, 'Kujawsko-Pomorskie', 'Samociążek', 'Dojazd do slipu jest nieutwardzony, prowadzi przez teren leśny. Nawierzchnia jest piaszczysta, co może utrudniać wodowanie cięższych jednostek. Brak wydzielonego miejsca na manewrowanie zestawem, co wymaga dużej wprawy. Obecnie slip jest w remoncie, jego nośność zostanie zwiększona po zakończeniu prac.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9727, 'W remoncie', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Piaszczysty', 'Łagodne', NULL, 0.8, 'Brak', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9728, 'Slip asfaltowy - Koronowo', 'slip-asfaltowy-koronowo-koronowo-9728', 'SLIP', 53.3043207, 17.9760807, 'Kujawsko-Pomorskie', 'Koronowo', 'Dojazd do slipu jest asfaltowy, dobrze utrzymany i łatwo dostępny. Nawierzchnia slipu wykonana jest z asfaltu, zapewniającego dobrą przyczepność. Miejsce na manewrowanie zestawem jest ograniczone, co wymaga ostrożności. Slip jest przystosowany do wodowania jednostek o masie do 2 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9728, 'Czynny', 'Tylko dla członków klubu', 'Płatny', 'Całodobowo', 'Asfaltowy', 'Strome', NULL, 1.4, 'Dostępny', TRUE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9729, 'Slip rzeczny - Jurków', 'slip-rzeczny-jurkow-jurkow-9729', 'SLIP', 50.3618979, 20.6441337, 'Świętokrzyskie', 'Jurków', 'Dojazd do slipu drogą utwardzoną, lecz wąską. Nawierzchnia slipu wykonana z płyt betonowych, zapewniająca dobrą przyczepność. Dostępne jest ograniczone miejsce na zestaw holowniczy. Nośność konstrukcji szacowana na 3,5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9729, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.2, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9730, 'Slip miejski - Poznań', 'slip-miejski-poznan-poznan-9730', 'SLIP', 52.4122281, 16.9441322, 'Wielkopolskie', 'Poznań', 'Łatwy dojazd z głównej drogi, dobrze oznakowany. Nawierzchnia slipu to solidne płyty betonowe, odporne na obciążenia. Duże, wydzielone miejsce na parking dla zestawów holowniczych. Nośność slipu wynosi do 5 ton.', NULL);
