INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9747, 'Slip Przystań Rzeczna - Warszawa', 'slip-przystan-rzeczna-warszawa-warszawa-9747', 'SLIP', 52.2986285, 20.993026, 'Mazowieckie', 'Warszawa', 'Dojazd do slipu odbywa się przez teren prywatny, który jest dobrze utrzymany. Nawierzchnia jest piaszczysta, stabilizowana dla lepszej przyczepności. Dostępne jest dużo miejsca na manewrowanie zestawem. Nośność slipu jest odpowiednia dla lekkich łodzi.', NULL);
