INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9749, 'Slip betonowy - Gdańsk Stogi', 'slip-betonowy-gdansk-stogi-gdansk-9749', 'SLIP', 54.33705, 18.937787, 'Pomorskie', 'Gdańsk', 'Do slipu prowadzi utwardzona droga dojazdowa. Nawierzchnia slipu wykonana jest z solidnego betonu, zapewniając dobrą przyczepność. Dostępne jest ograniczone miejsce na manewrowanie zestawem. Nośność konstrukcji przystosowana jest do większości jednostek rekreacyjnych.', NULL);
