INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9750, 'Slip nad jeziorem Nowogardzkim', 'slip-nad-jeziorem-nowogardzkim-nowogard-9750', 'SLIP', 53.6711368, 15.1124283, 'Zachodniopomorskie', 'Nowogard', 'Dojazd do slipu odbywa się drogą gruntową, wymagającą ostrożności. Nawierzchnia slipu jest żwirowa, co może wymagać napędu 4x4 przy większych jednostkach. Dostępne jest dużo miejsca na swobodne manewrowanie zestawem. Konstrukcja slipu jest przystosowana do średnich łodzi i skuterów wodnych.', NULL);
