INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9751, 'Slip rzeczny - Wały (Odra)', 'slip-rzeczny-waly-odra-waly-9751', 'SLIP', 51.2616527, 16.7710016, 'Dolnośląskie', 'Wały', 'Dojazd do slipu jest utwardzony, ale wąski w niektórych miejscach. Nawierzchnia slipu jest piaszczysta, co zapewnia dobrą przyczepność dla lekkich jednostek. Miejsce na manewrowanie zestawem jest umiarkowane, wymaga pewnej wprawy. Slip jest przeznaczony dla małych i średnich łodzi motorowych.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9751, 'W remoncie', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Piaszczysty', 'Umiarkowane', NULL, 1.5, 'Ograniczony', TRUE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9752, 'Slip rekreacyjny - Karbowo (Jezioro Niskie Brodno)', 'slip-rekreacyjny-karbowo-jezioro-niskie-brodno-karbowo-9752', 'SLIP', 53.2819246, 19.4766297, 'Kujawsko-Pomorskie', 'Karbowo', 'Dojazd do slipu jest drogą polną, dostępną tylko w dobrych warunkach pogodowych. Nawierzchnia slipu to trawa, odpowiednia dla kajaków i małych łodzi wiosłowych. Dostępne jest ograniczone miejsce na manewrowanie zestawem. Slip ma niską nośność, przeznaczony jest dla bardzo lekkich jednostek.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9752, 'Czynny', 'Dla klientów', 'W cenie usługi', 'Całodobowo', 'Trawa', 'Łagodne', NULL, 0.8, 'Na terenie obiektu', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9753, 'Slip na Wiśle - Żarki', 'slip-na-wisle-zarki-zarki-9753', 'SLIP', 50.0629605, 19.3486922, 'Małopolskie', 'Żarki', 'Dojazd do slipu jest drogą asfaltową, w dobrym stanie. Nawierzchnia slipu wykonana jest z solidnych płyt betonowych, zapewniając stabilność. Dostępne jest dużo miejsca na swobodne manewrowanie zestawem. Nośność slipu pozwala na wodowanie dużych łodzi motorowych i jachtów.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9753, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 2, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9754, 'Slip betonowy - Grudziądz', 'slip-betonowy-grudziadz-grudziadz-9754', 'SLIP', 53.4914159, 18.7454391, 'Kujawsko-Pomorskie', 'Grudziądz', 'Do slipu prowadzi utwardzona droga dojazdowa, zapewniająca łatwy dostęp. Nawierzchnia slipu jest betonowa, w dobrym stanie technicznym, co gwarantuje stabilność. Dostępne jest obszerne miejsce na zestaw pojazd-przyczepa, ułatwiające manewrowanie. Nośność konstrukcji jest wystarczająca dla większości jednostek pływających.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9754, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Betonowy', 'Umiarkowane', NULL, 1.8, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9755, 'Slip rzeczny - Mała Nieszawka', 'slip-rzeczny-mala-nieszawka-mala-nieszawka-9755', 'SLIP', 53.0008372, 18.5600453, 'Kujawsko-Pomorskie', 'Mała Nieszawka', 'Dojazd do slipu jest prosty, drogą asfaltową, z dobrą widocznością. Nawierzchnia wykonana jest z betonu, co zapewnia solidne podłoże do wodowania. W pobliżu slipu znajduje się wystarczająco dużo miejsca na swobodne ustawienie zestawu. Konstrukcja slipu jest przystosowana do obciążenia typowymi łodziami motorowymi.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9755, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Betonowy', 'Łagodne', NULL, 1.5, 'Dostępny', FALSE, NULL, 'Dużo miejsca', NULL);
