INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9766, 'Slip Dymaczewo Nowe - Jezioro Dymaczewskie', 'slip-dymaczewo-nowe-jezioro-dymaczewskie-dymaczewo-nowe-9766', 'SLIP', 52.2307972, 16.7646273, 'Wielkopolskie', 'Dymaczewo Nowe', 'Dojazd do slipu jest wąski i nieutwardzony, co może być wyzwaniem. Nawierzchnia żwirowa wymaga uwagi podczas wodowania, szczególnie przy większych jednostkach. Brak dedykowanego parkingu dla przyczep w bezpośrednim sąsiedztwie. Slip jest odpowiedni dla małych łodzi do 1 tony.', NULL);
