INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9767, 'Slip Tomaszów Mazowiecki - Zalew Sulejowski (Północ)', 'slip-tomaszow-mazowiecki-zalew-sulejowski-polnoc-tomaszow-mazowiecki-9767', 'SLIP', 51.5188739, 20.0325383, 'Łódzkie', 'Tomaszów Mazowiecki', 'Dojazd do slipu jest asfaltowy i szeroki, zapewniający komfortowy dostęp. Nawierzchnia betonowa jest w dobrym stanie, gwarantując bezpieczne wodowanie. Dostępny jest parking dla przyczep na terenie przyległego ośrodka. Slip umożliwia wodowanie jednostek o masie do 4 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9767, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Betonowy', 'Umiarkowane', NULL, 1.8, 'Na terenie obiektu', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9768, 'Slip Tomaszów Mazowiecki - Zalew Sulejowski (Południe)', 'slip-tomaszow-mazowiecki-zalew-sulejowski-poludnie-tomaszow-mazowiecki-9768', 'SLIP', 51.5182438, 20.0315672, 'Łódzkie', 'Tomaszów Mazowiecki', 'Dojazd do slipu jest polną drogą, wymagającą pojazdu z napędem 4x4. Nawierzchnia piaszczysta może utrudniać wodowanie cięższych jednostek. Parking dla przyczep jest ograniczony do pobocza drogi. Slip jest przeznaczony dla lekkich łodzi i skuterów wodnych o masie do 0.8 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9768, 'W remoncie', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Piaszczysty', 'Łagodne', NULL, 1, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9769, 'Slip betonowy - Gdańsk Stocznia', 'slip-betonowy-gdansk-stocznia-gdansk-9769', 'SLIP', 54.3529609, 18.635605, 'Pomorskie', 'Gdańsk', 'Dojazd do slipu jest wygodny, prowadzi drogą asfaltową z dobrym oznakowaniem. Nawierzchnia slipu wykonana jest z solidnych płyt betonowych, zapewniających stabilność. Dostępne jest ograniczone miejsce na manewrowanie zestawem z przyczepą. Nośność konstrukcji pozwala na wodowanie jednostek o masie do 2,5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9769, 'Czynny', 'Publiczny', 'Płatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.8, 'Ograniczony', TRUE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9770, 'Slip żwirowy - Jezioro Mucharskie', 'slip-zwirowy-jezioro-mucharskie-mucharz-9770', 'SLIP', 49.8164552, 19.5459283, 'Małopolskie', 'Mucharz', 'Dojazd do slipu odbywa się drogą gruntową, która może być wymagająca po opadach. Nawierzchnia slipu to utwardzony żwir, zapewniający wystarczającą przyczepność. Na terenie obiektu znajduje się dużo miejsca na manewrowanie zestawem. Nośność slipu jest odpowiednia dla mniejszych jednostek do 1,5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9770, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1.2, 'Dostępny', FALSE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9771, 'Slip z płyt betonowych - Jezioro Chrzypskie', 'slip-z-plyt-betonowych-jezioro-chrzypskie-chrzypsko-wielkie-9771', 'SLIP', 52.6257693, 16.2156274, 'Wielkopolskie', 'Chrzypsko Wielkie', 'Dojazd do slipu jest komfortowy, prowadzi drogą utwardzoną do samego brzegu. Nawierzchnia składa się z solidnych płyt betonowych, gwarantujących stabilność. W pobliżu slipu jest wystarczająco miejsca na swobodne manewrowanie zestawem. Nośność konstrukcji pozwala na wodowanie jednostek o masie do 2 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9771, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.5, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9772, 'Slip klubowy - Jezioro Żnińskie Małe', 'slip-klubowy-jezioro-zninskie-male-znin-9772', 'SLIP', 52.839055, 17.7228904, 'Kujawsko-Pomorskie', 'Żnin', 'Dojazd do slipu jest dobrze utrzymany, prowadzi przez teren klubu żeglarskiego. Nawierzchnia slipu to wytrzymały beton, zapewniający doskonałą przyczepność. Dostępne jest ograniczone miejsce na manewrowanie zestawem, wymaga wprawy. Nośność konstrukcji pozwala na wodowanie jednostek o masie do 3 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9772, 'Czynny', 'Tylko dla członków klubu', 'W cenie usługi', 'Całodobowo', 'Betonowy', 'Umiarkowane', NULL, 2, 'Na terenie obiektu', TRUE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9773, 'Slip betonowy - Przystań Żnin', 'slip-betonowy-przystan-znin-znin-9773', 'SLIP', 52.8389813, 17.7228863, 'Kujawsko-Pomorskie', 'Żnin', 'Dojazd do slipu jest utwardzony, łatwy do pokonania dla każdego pojazdu. Nawierzchnia slipu wykonana jest z solidnego betonu, gwarantującego bezpieczeństwo. Miejsca na manewrowanie zestawem jest wystarczająco, choć w sezonie bywa ciasno. Nośność konstrukcji pozwala na wodowanie jednostek o masie do 2,8 tony.', NULL);
