INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9774, 'Slip betonowy - Miałkie', 'slip-betonowy-mialkie-mialkie-9774', 'SLIP', 52.5015756, 18.6502243, 'Kujawsko-Pomorskie', 'Miałkie', 'Do slipu prowadzi utwardzona droga gruntowa, łatwo dostępna dla zestawów z przyczepą. Nawierzchnia wykonana jest z solidnych płyt betonowych, zapewniających dobrą przyczepność. Miejsce na manewrowanie zestawem jest wystarczające, choć w sezonie może być ograniczone. Nośność slipu pozwala na wodowanie jednostek o masie do 3 ton.', NULL);
