INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9775, 'Slip żwirowy - Rakowice Małe (Zachodni)', 'slip-zwirowy-rakowice-male-zachodni-rakowice-male-9775', 'SLIP', 51.1538576, 15.5501538, 'Dolnośląskie', 'Rakowice Małe', 'Dojazd do slipu odbywa się drogą polną, wymagającą ostrożności, szczególnie po opadach. Nawierzchnia żwirowa zapewnia umiarkowaną przyczepność, zaleca się napęd 4x4 dla cięższych jednostek. Miejsce na manewrowanie jest ograniczone, wymaga wprawy przy większych zestawach. Nośność slipu jest szacowana na jednostki do 1.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9775, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9776, 'Slip piaszczysty - Rakowice Małe (Wschodni)', 'slip-piaszczysty-rakowice-male-wschodni-rakowice-male-9776', 'SLIP', 51.1530073, 15.5500904, 'Dolnośląskie', 'Rakowice Małe', 'Dojazd do slipu jest łatwy, prowadzi przez utwardzoną drogę dojazdową do ośrodka. Nawierzchnia piaszczysta wymaga ostrożności, szczególnie przy cięższych łodziach, zalecane jest użycie mat trakcyjnych. Przestrzeń do manewrowania jest wystarczająca, ale należy uważać na miękki piasek. Slip przeznaczony jest dla jednostek o masie do 1 tony.', NULL);
