INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9777, 'Slip plażowy - Mościska (Jezioro Narty)', 'slip-plazowy-mosciska-jezioro-narty-mosciska-9777', 'SLIP', 53.6673753, 21.4620113, 'Warmińsko-Mazurskie', 'Mościska', 'Dojazd do slipu jest dobrze oznakowany, prowadzi przez teren prywatny z wymaganym pozwoleniem. Nawierzchnia piaszczysta jest stabilna w płytkiej wodzie, ale wymaga uwagi przy głębszym zanurzeniu. Miejsca na manewrowanie jest dużo, jednak parking dla przyczep jest ograniczony. Slip jest odpowiedni dla małych i średnich jednostek, do 1.2 tony.', NULL);
