INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9787, 'Slip rzeczny - Gołaszewo Wisła', 'slip-rzeczny-golaszewo-wisla-golaszewo-9787', 'SLIP', 52.5673588, 19.1085061, 'Kujawsko-Pomorskie', 'Gołaszewo', 'Dojazd do slipu jest polną drogą, wymagającą ostrożności, szczególnie po opadach. Nawierzchnia slipu jest żwirowa, co może utrudniać wodowanie cięższych jednostek. Miejsce na manewrowanie zestawem jest wąskie, wymaga doświadczenia kierowcy. Nośność slipu jest ograniczona, zalecane dla małych łodzi do 1 tony.', NULL);
