INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9815, 'Slip żwirowy - Jezioro Boczne', 'slip-zwirowy-jezioro-boczne-bogaczewo-9815', 'SLIP', 53.968679, 21.7778719, 'Warmińsko-Mazurskie', 'Bogaczewo', 'Dojazd do slipu prowadzi polną drogą, która może być trudna po opadach deszczu. Nawierzchnia slipu jest żwirowa, co wymaga ostrożności przy wodowaniu cięższych jednostek. Miejsce na zestaw jest ograniczone, zaleca się wcześniejsze zaplanowanie manewru. Nośność terenu pozwala na wodowanie łodzi o masie do 1.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9815, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1.2, 'Ograniczony', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9816, 'Slip piaszczysty - Zalew Nielisz', 'slip-piaszczysty-zalew-nielisz-nawoz-9816', 'SLIP', 50.7942645, 23.025971, 'Lubelskie', 'Nawóz', 'Dojazd do slipu jest łatwy, drogą asfaltową prowadzącą bezpośrednio do brzegu. Nawierzchnia slipu jest piaszczysta, co może utrudniać wodowanie pojazdów z napędem na jedną oś. Dostępne jest wystarczające miejsce na zestaw, ale należy uważać na miękki piasek. Nośność podłoża jest odpowiednia dla małych i średnich jednostek do 1 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9816, 'W remoncie', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Piaszczysty', 'Łagodne', NULL, 1, 'Dostępny', FALSE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9817, 'Slip betonowy - Nielisz Port', 'slip-betonowy-nielisz-port-nielisz-9817', 'SLIP', 50.7830216, 23.0300128, 'Lubelskie', 'Nielisz', 'Dojazd do slipu jest bardzo dobry, bezpośrednio z drogi wojewódzkiej. Nawierzchnia slipu jest w całości betonowa, zapewniająca doskonałą przyczepność i trwałość. Obok slipu znajduje się duży plac manewrowy, idealny dla długich zestawów. Nośność slipu pozwala na bezpieczne wodowanie jednostek o masie do 5 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9817, 'Czynny', 'Dla klientów', 'W cenie usługi', 'Całodobowo', 'Betonowy', 'Umiarkowane', NULL, 2, 'Na terenie obiektu', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9818, 'Slip asfaltowy - Jezioro Mucharskie', 'slip-asfaltowy-jezioro-mucharskie-swinna-poreba-9818', 'SLIP', 49.8299561, 19.5259407, 'Małopolskie', 'Świnna Poręba', 'Dojazd do slipu jest wygodny, drogą gminną o dobrej nawierzchni. Nawierzchnia slipu wykonana jest z asfaltu, co zapewnia płynne wodowanie, jednak może być śliska w deszczu. Miejsce na zestaw jest wystarczające, ale wymaga wprawy ze względu na otoczenie. Nośność slipu jest odpowiednia dla jednostek do 2.5 tony.', NULL);
