INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9835, 'Slip z płyt betonowych - Nowy Dwór Mazowiecki', 'slip-z-plyt-betonowych-nowy-dwor-mazowiecki-nowy-dwor-mazowiecki-9835', 'SLIP', 52.4348498, 20.7002186, 'Mazowieckie', 'Nowy Dwór Mazowiecki', 'Dojazd do slipu prowadzi drogą gruntową, wymagającą ostrożności w deszczowe dni. Nawierzchnia slipu to solidne płyty betonowe, zapewniające stabilność. Miejsce do manewrowania zestawem jest ograniczone, co wymaga pewnej wprawy. Slip przystosowany jest do wodowania jednostek o masie do 2 ton.', NULL);
