INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9836, 'Slip dla klientów - Kraków (Zabłocie)', 'slip-dla-klientow-krakow-zablocie-krakow-9836', 'SLIP', 50.0348338, 20.0789491, 'Małopolskie', 'Kraków', 'Dojazd do slipu jest utwardzony i dobrze oznakowany, łatwy do znalezienia. Nawierzchnia slipu wykonana jest z trwałego betonu, gwarantującego bezpieczeństwo. Na terenie obiektu dostępny jest parking dla przyczep i samochodów. Nośność slipu pozwala na wodowanie jednostek o masie do 4 ton.', NULL);
