INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9837, 'Slip piaszczysty - Chrzanów', 'slip-piaszczysty-chrzanow-chrzanow-9837', 'SLIP', 50.1341053, 19.4476915, 'Małopolskie', 'Chrzanów', 'Dojazd do slipu jest nieutwardzony, prowadzi przez teren leśny, zalecany napęd 4x4. Nawierzchnia slipu to naturalny piasek, odpowiedni dla mniejszych jednostek. Dostępne jest dużo miejsca do manewrowania, jednak parking dla przyczep jest niedostępny. Slip przeznaczony jest dla jednostek o masie do 1 tony.', NULL);
