INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9839, 'Slip betonowy - Krzewiny', 'slip-betonowy-krzewiny-krzewiny-9839', 'SLIP', 53.6368394, 18.5663127, 'Kujawsko-Pomorskie', 'Krzewiny', 'Dojazd do slipu drogą utwardzoną, zapewniającą łatwy dostęp. Nawierzchnia slipu jest betonowa, solidna i w dobrym stanie technicznym. Duże pole manewrowe umożliwia swobodne operowanie zestawem łodzi z przyczepą. Nośność konstrukcji przewidziana jest dla jednostek pływających o masie do 3 ton.', NULL);
