INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9840, 'Slip piaszczysty - Imionek', 'slip-piaszczysty-imionek-imionek-9840', 'SLIP', 53.6398883, 21.8233854, 'Warmińsko-Mazurskie', 'Imionek', 'Dojazd do slipu drogą gruntową, wymagającą ostrożności, szczególnie po opadach. Nawierzchnia slipu jest piaszczysta, odpowiednia dla lekkich jednostek i wymaga uwagi przy wodowaniu. Miejsce na zestaw jest ograniczone, zaleca się użycie mniejszych pojazdów i przyczep. Nośność naturalna, odpowiednia dla łodzi o niewielkiej masie.', NULL);
