INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9848, 'Slip piaszczysty - Krutla', 'slip-piaszczysty-krutla-krutla-9848', 'SLIP', 52.0812533, 16.0455787, 'Wielkopolskie', 'Krutla', 'Dojazd do slipu jest nieutwardzony, piaszczysty, wymaga napędu 4x4 w trudniejszych warunkach. Nawierzchnia piaszczysta jest odpowiednia dla lekkich jednostek, ale może być zdradliwa. Miejsce na zestaw jest ograniczone, ale teren otwarty pozwala na swobodne manewrowanie. Slip przeznaczony jest dla jednostek do 0.8 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9848, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Piaszczysty', 'Łagodne', NULL, 0.7, 'Ograniczony', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9849, 'Slip betonowy - Czerwonak', 'slip-betonowy-czerwonak-czerwonak-9849', 'SLIP', 52.465587, 16.9770038, 'Wielkopolskie', 'Czerwonak', 'Dojazd do slipu jest utwardzony i łatwy. Nawierzchnia slipu wykonana jest z betonu, zapewniając dobrą przyczepność. Dostępne jest dużo miejsca do manewrowania zestawem z przyczepą. Slip jest przystosowany do wodowania jednostek o średniej masie.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9849, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Betonowy', 'Łagodne', NULL, 1.5, 'Dostępny', FALSE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9850, 'Slip nad Wisłą - Warszawa', 'slip-nad-wisla-warszawa-warszawa-9850', 'SLIP', 52.2472782, 21.0312104, 'Mazowieckie', 'Warszawa', 'Dojazd do slipu prowadzi drogą gruntową, wymagającą uwagi. Nawierzchnia składa się z płyt betonowych, które mogą być śliskie. Miejsce na zestaw jest ograniczone, co wymaga wprawy przy manewrowaniu. Slip jest odpowiedni dla mniejszych i średnich łodzi.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9850, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.8, 'Ograniczony', TRUE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9851, 'Slip rzeczny - Łączany', 'slip-rzeczny-laczany-laczany-9851', 'SLIP', 49.9889578, 19.5778412, 'Małopolskie', 'Łączany', 'Dojazd do slipu jest komfortowy, drogą asfaltową. Nawierzchnia slipu to solidne płyty betonowe, gwarantujące stabilność. Wokół slipu znajduje się wystarczająco miejsca na swobodne manewrowanie zestawem. Obiekt jest przeznaczony do wodowania większości typów jednostek pływających.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9851, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Łagodne', NULL, 1.2, 'Dostępny', FALSE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9852, 'Slip turystyczny - Maniowy (Czorsztyn)', 'slip-turystyczny-maniowy-czorsztyn-maniowy-9852', 'SLIP', 49.4479958, 20.278991, 'Małopolskie', 'Maniowy', 'Dojazd do slipu jest dobrze oznakowany, drogą szutrową. Nawierzchnia żwirowa zapewnia umiarkowaną przyczepność, należy zachować ostrożność. Miejsce na zestaw jest ograniczone, co może utrudniać manewry. Slip jest odpowiedni dla mniejszych jednostek, głównie motorówek.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9852, 'Czynny', 'Dla klientów', 'W cenie usługi', 'Całodobowo', 'Żwirowy', 'Umiarkowane', NULL, 1, 'Na terenie obiektu', TRUE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9853, 'Slip plażowy - Maniowy (Czorsztyn)', 'slip-plazowy-maniowy-czorsztyn-maniowy-9853', 'SLIP', 49.4471883, 20.2782806, 'Małopolskie', 'Maniowy', 'Dojazd do slipu jest piaszczysty, co może być wyzwaniem dla pojazdów 2WD. Nawierzchnia slipu to piasek, co wymaga ostrożności przy wodowaniu. Dostępne jest dużo miejsca na plaży, ale brak dedykowanego parkingu dla zestawu. Slip jest idealny dla kajaków i małych łodzi wiosłowych.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9853, 'W remoncie', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Piaszczysty', 'Łagodne', NULL, 0.8, 'Brak', FALSE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9854, 'Slip żwirowy - Maniowy', 'slip-zwirowy-maniowy-maniowy-9854', 'SLIP', 49.4521163, 20.2621384, 'Małopolskie', 'Maniowy', 'Dojazd drogą utwardzoną, ostatni odcinek żwirowy. Nawierzchnia slipu to dobrze ubity żwir, zapewniający dobrą przyczepność. Dostępne jest ograniczone miejsce na manewrowanie zestawem oraz parking dla przyczep na terenie obiektu. Nośność slipu jest wystarczająca dla większości jednostek rekreacyjnych.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9854, 'Czynny', 'Prywatny', 'Płatny', 'Całodobowo', 'Żwirowy', 'Umiarkowane', NULL, 1.2, 'Na terenie obiektu', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9855, 'Slip betonowy - Niedzica-Zamek', 'slip-betonowy-niedzica-zamek-niedzica-zamek-9855', 'SLIP', 49.4259533, 20.3102644, 'Małopolskie', 'Niedzica-Zamek', 'Dojazd asfaltową drogą gminną, łatwy i komfortowy. Nawierzchnia slipu wykonana jest z solidnych płyt betonowych, zapewniających stabilność. Dostępne jest dużo miejsca na manewrowanie zestawem oraz obszerny parking dla przyczep w pobliżu. Slip charakteryzuje się wysoką nośnością, odpowiednią dla cięższych jednostek.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9855, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Betonowy', 'Łagodne', NULL, 1.8, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9856, 'Slip nad Odrą - Osłonin', 'slip-nad-odra-oslonin-oslonin-9856', 'SLIP', 51.9513064, 16.2066835, 'Lubuskie', 'Osłonin', 'Dojazd drogą gruntową, wymagający ostrożności, szczególnie po deszczu. Nawierzchnia slipu to solidne płyty betonowe, zapewniające dobrą przyczepność. Miejsce na manewrowanie zestawem jest ograniczone, a parking dla przyczep dostępny w niewielkiej odległości. Nośność slipu jest wystarczająca dla średnich jednostek.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9856, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.5, 'Ograniczony', FALSE, NULL, 'Wąsko', NULL);
