INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9869, 'Slip Miejski - Ruda Śląska', 'slip-miejski-ruda-slaska-ruda-slaska-9869', 'SLIP', 50.3030786, 18.8713163, 'Śląskie', 'Ruda Śląska', 'Dojazd do slipu jest asfaltowy, lecz w końcowym odcinku wymaga uwagi ze względu na wąską drogę. Nawierzchnia slipu wykonana jest z solidnych płyt betonowych, zapewniających dobrą przyczepność. Miejsce na zestaw z przyczepą jest ograniczone, co wymaga precyzyjnego manewrowania. Nośność slipu pozwala na wodowanie jednostek o masie do 2 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9869, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.2, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9870, 'Slip Portowy - Giżycko', 'slip-portowy-gizycko-gizycko-9870', 'SLIP', 54.0180802, 21.7434893, 'Warmińsko-Mazurskie', 'Giżycko', 'Dojazd do slipu jest komfortowy, prowadzi szeroką drogą utwardzoną, bez problemów z mijaniem. Nawierzchnia slipu to równy, dobrze utrzymany beton, idealny do wodowania większych jednostek. Dostępne jest obszerne miejsce na zestaw z przyczepą, co ułatwia operacje. Slip przystosowany jest do wodowania jednostek o masie do 3.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9870, 'Czynny', 'Publiczny', 'Płatny', 'Całodobowo', 'Betonowy', 'Łagodne', NULL, 1.8, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9871, 'Slip nad Wartą - Poznań', 'slip-nad-warta-poznan-poznan-9871', 'SLIP', 52.4058008, 16.962064, 'Wielkopolskie', 'Poznań', 'Dojazd do slipu jest asfaltowy, jednak w pobliżu rzeki droga staje się węższa. Nawierzchnia slipu wykonana jest z płyt betonowych, które są w dobrym stanie technicznym. Miejsce na zestaw z przyczepą jest ograniczone, co może utrudniać manewrowanie większymi pojazdami. Nośność slipu pozwala na wodowanie jednostek o masie do 1.8 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9871, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1, 'Ograniczony', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9872, 'Slip Leśny - Rudnia', 'slip-lesny-rudnia-rudnia-9872', 'SLIP', 52.9518391, 23.7788167, 'Podlaskie', 'Rudnia', 'Dojazd do slipu prowadzi drogą szutrową przez las, wymagając ostrożności, ale jest przejezdny. Nawierzchnia slipu jest żwirowa, dobrze utwardzona, zapewniająca stabilność. Dostępne jest dużo miejsca na zestaw z przyczepą, co ułatwia manewrowanie nawet dużymi pojazdami. Slip jest odpowiedni dla jednostek o masie do 1.5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9872, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 0.8, 'Dostępny', FALSE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9873, 'Slip Wiejski - Gawrony', 'slip-wiejski-gawrony-gawrony-9873', 'SLIP', 52.0338295, 17.0427935, 'Wielkopolskie', 'Gawrony', 'Dojazd do slipu jest polną drogą, która może być trudna po opadach deszczu. Nawierzchnia slipu to trawa z elementami piasku, co wymaga ostrożności przy wodowaniu. Brak wydzielonego miejsca na zestaw z przyczepą, parkowanie odbywa się na poboczu. Slip jest przeznaczony dla lekkich jednostek o masie do 0.8 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9873, 'W remoncie', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Trawa', 'Łagodne', NULL, 0.7, 'Brak', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9874, 'Slip rekreacyjny - Lisia Góra', 'slip-rekreacyjny-lisia-gora-lisia-gora-9874', 'SLIP', 52.5766044, 15.4308008, 'Lubuskie', 'Lisia Góra', 'Dojazd do slipu odbywa się drogą gruntową, dobrze utrzymaną. Nawierzchnia slipu jest żwirowa, stabilna i zapewnia dobrą przyczepność. Dostępne jest ograniczone miejsce na zestaw samochodowy z przyczepą w pobliżu. Slip jest przystosowany do wodowania jednostek o masie do 1,5 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9874, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1, 'Ograniczony', FALSE, NULL, 'Dużo miejsca', NULL);
