INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9891, 'Slip piaszczysty - Drawsko Pomorskie', 'slip-piaszczysty-drawsko-pomorskie-gmina-drawsko-pomorskie-9891', 'SLIP', 53.4114462, 15.8931303, 'Zachodniopomorskie', 'gmina Drawsko Pomorskie', 'Dojazd do slipu prowadzi drogą gruntową, wymagającą ostrożności. Nawierzchnia slipu jest piaszczysta, co może wymagać napędu 4x4 przy cięższych jednostkach. Dostępne jest dużo miejsca na manewrowanie zestawem, szczególnie poza sezonem. Nośność slipu jest odpowiednia dla lekkich i średnich łodzi.', NULL);
