INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9932, 'Slip żwirowy - Mechelinki', 'slip-zwirowy-mechelinki-mechelinki-9932', 'SLIP', 54.6118851, 18.5130719, 'Pomorskie', 'Mechelinki', 'Dojazd do slipu jest prywatny, wymaga wcześniejszego uzgodnienia z właścicielem. Nawierzchnia slipu jest żwirowa, co wymaga ostrożności przy wodowaniu cięższych jednostek. Miejsce do manewrowania jest ograniczone, co może utrudniać operacje większymi zestawami. Slip najlepiej sprawdza się dla lekkich łodzi i skuterów wodnych.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9932, 'Czynny', 'Prywatny', 'Płatny', 'Całodobowo', 'Żwirowy', 'Umiarkowane', NULL, 0.8, 'Na terenie obiektu', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9933, 'Slip piaszczysty - Jemiołów', 'slip-piaszczysty-jemiolow-jemiolow-9933', 'SLIP', 52.3370635, 15.230004, 'Lubuskie', 'Jemiołów', 'Dojazd do slipu jest polną drogą, która może być trudna do pokonania po opadach deszczu. Nawierzchnia slipu jest piaszczysta, co wymaga napędu 4x4 dla cięższych jednostek. Dostępne jest dużo miejsca na manewrowanie, ale brak wydzielonego parkingu dla przyczep. Slip jest odpowiedni dla małych łodzi i kajaków, z ograniczoną nośnością.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9933, 'Nieczynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Piaszczysty', 'Łagodne', NULL, 1, 'Brak', FALSE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9934, 'Slip rzeczny - Jemiołów', 'slip-rzeczny-jemiolow-jemiolow-9934', 'SLIP', 52.3370023, 15.2293281, 'Lubuskie', 'Jemiołów', 'Dojazd do slipu odbywa się drogą utwardzoną, lecz w końcowym odcinku może być żwirowa. Nawierzchnia slipu jest żwirowa, co zapewnia dobrą przyczepność dla pojazdów. W pobliżu dostępny jest obszerny teren na swobodne manewrowanie zestawem z przyczepą. Konstrukcja slipu, choć żwirowa, jest wystarczająco stabilna dla większości jednostek pływających.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9934, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Umiarkowane', NULL, 1.2, 'Dostępny', FALSE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9935, 'Slip jeziorny - Odrowąż', 'slip-jeziorny-odrowaz-odrowaz-9935', 'SLIP', 50.5047117, 17.9474325, 'Opolskie', 'Odrowąż', 'Dojazd do slipu jest łatwy, prowadzi drogą gruntową dobrze utrzymaną. Nawierzchnia slipu jest piaszczysta, idealna dla lekkich łodzi i skuterów wodnych. Dostępne jest obszerne miejsce do przygotowania i wodowania zestawu. Slip charakteryzuje się naturalną nośnością gruntu, odpowiednią dla jednostek o umiarkowanej wadze.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9935, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Piaszczysty', 'Łagodne', NULL, 1, 'Dostępny', FALSE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9936, 'Slip miejski - Ostrołęka', 'slip-miejski-ostroleka-ostroleka-9936', 'SLIP', 53.0907399, 21.5671747, 'Mazowieckie', 'Ostrołęka', 'Dojazd do slipu jest asfaltowy, co gwarantuje komfortowy dostęp o każdej porze roku. Nawierzchnia slipu wykonana jest z solidnych płyt betonowych, zapewniających wysoką trwałość i stabilność. Wokół slipu znajduje się wystarczająco dużo miejsca na swobodne manewrowanie dużym zestawem. Nośność konstrukcji betonowej pozwala na wodowanie ciężkich jednostek pływających.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9936, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.8, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9937, 'Slip wiślany - Kraków', 'slip-wislany-krakow-krakow-9937', 'SLIP', 50.0336828, 19.9933513, 'Małopolskie', 'Kraków', 'Dojazd do slipu w centrum miasta może być ograniczony, zaleca się wcześniejsze sprawdzenie trasy. Nawierzchnia slipu jest drewniana, co wymaga ostrożności, zwłaszcza przy mokrej pogodzie. Miejsce na manewrowanie zestawem jest ograniczone, wymaga wprawy i precyzji. Konstrukcja drewniana jest odpowiednia dla mniejszych i średnich jednostek, należy unikać przeciążania.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9937, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Drewniany', 'Umiarkowane', NULL, 1.3, 'Ograniczony', TRUE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9938, 'Slip rekreacyjny - Mostki', 'slip-rekreacyjny-mostki-mostki-9938', 'SLIP', 51.0403695, 20.9132617, 'Świętokrzyskie', 'Mostki', 'Dojazd do slipu jest komfortowy, prowadzi drogą utwardzoną bezpośrednio do brzegu. Nawierzchnia slipu jest betonowa, co zapewnia doskonałą stabilność i odporność na ścieranie. Dostępne jest dużo miejsca na parkowanie i manewrowanie zestawem z przyczepą. Solidna konstrukcja betonowa gwarantuje wysoką nośność dla różnorodnych jednostek pływających.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9938, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Betonowy', 'Strome', NULL, 1.5, 'Dostępny', FALSE, NULL, 'Dużo miejsca', NULL);
