INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9955, 'Slip żwirowy - Nowy Dwór Mazowiecki', 'slip-zwirowy-nowy-dwor-mazowiecki-nowy-dwor-mazowiecki-9955', 'SLIP', 52.437259, 20.689179, 'Mazowieckie', 'Nowy Dwór Mazowiecki', 'Dojazd drogą gruntową, ostatnie 50 metrów utwardzone żwirem. Nawierzchnia żwirowa wymaga ostrożności podczas wodowania. Ograniczone miejsce na manewrowanie zestawem z przyczepą. Nośność wystarczająca dla średnich jednostek pływających.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9955, 'Czynny', 'Dla klientów', 'Płatny', 'Całodobowo', 'Żwirowy', 'Łagodne', NULL, 1.2, 'Na terenie obiektu', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9956, 'Slip z płyt betonowych - Głusk', 'slip-z-plyt-betonowych-glusk-glusk-9956', 'SLIP', 52.4201219, 20.5780017, 'Mazowieckie', 'Głusk', 'Dojazd drogą lokalną, ostatni odcinek nieutwardzony. Nawierzchnia wykonana z solidnych płyt betonowych, zapewniających stabilność. Dostępne miejsce na zestaw, ale wymaga precyzji manewrowania. Nośność przewidziana dla większości łodzi motorowych.', NULL);
