INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9957, 'Slip trawiasty - Narty (Jezioro Narty)', 'slip-trawiasty-narty-jezioro-narty-narty-9957', 'SLIP', 53.5404892, 20.78463, 'Warmińsko-Mazurskie', 'Narty', 'Dojazd drogą polną, ostatni odcinek może być błotnisty po deszczu. Nawierzchnia trawiasta, odpowiednia dla lekkich łodzi i pontonów. Dostępne obszerne miejsce na manewrowanie zestawem. Nośność ograniczona do małych i średnich jednostek.', NULL);
