INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9958, 'Slip piaszczysty - Ryn (Jezioro Ryńskie)', 'slip-piaszczysty-ryn-jezioro-rynskie-ryn-9958', 'SLIP', 53.9305318, 21.5358194, 'Warmińsko-Mazurskie', 'Ryn', 'Dojazd drogą utwardzoną, ostatnie metry do jeziora piaszczyste. Nawierzchnia piaszczysta, wymaga napędu 4x4 dla cięższych łodzi. Ograniczone miejsce na manewrowanie, ale wystarczające dla wprawnych kierowców. Nośność odpowiednia dla większości jednostek rekreacyjnych.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9958, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Piaszczysty', 'Umiarkowane', NULL, 1.3, 'Ograniczony', TRUE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9959, 'Slip rzeczny - Drezdenko', 'slip-rzeczny-drezdenko-drezdenko-9959', 'SLIP', 52.8521536, 15.8444776, 'Lubuskie', 'Drezdenko', 'Dojazd do slipu drogą utwardzoną, łatwy i bezproblemowy. Nawierzchnia wykonana z solidnych płyt betonowych, zapewniająca dobrą przyczepność. Dostępne jest obszerne miejsce na zestaw samochodowy z przyczepą. Slip jest przystosowany do wodowania jednostek o masie do 3 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9959, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.8, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9960, 'Slip nad jeziorem - Trzciel', 'slip-nad-jeziorem-trzciel-trzciel-9960', 'SLIP', 52.3620885, 15.8779339, 'Lubuskie', 'Trzciel', 'Dojazd do slipu wąską drogą gruntową, wymagającą ostrożności. Nawierzchnia betonowa, w dobrym stanie, choć miejscami z drobnymi ubytkami. Miejsce na manewrowanie zestawem jest ograniczone, szczególnie w sezonie. Slip jest odpowiedni dla łodzi o masie do 2 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9960, 'Czynny', 'Publiczny', 'Płatny', 'Całodobowo', 'Betonowy', 'Łagodne', NULL, 1.2, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9961, 'Slip Port Czorsztyn - Maniowy', 'slip-port-czorsztyn-maniowy-maniowy-9961', 'SLIP', 49.4453179, 20.2690472, 'Małopolskie', 'Maniowy', 'Dojazd do slipu drogą asfaltową, dobrze utrzymaną i oznakowaną. Nawierzchnia slipu jest asfaltowa, solidna i szeroka, idealna do wodowania większych jednostek. Na terenie portu dostępny jest duży parking dla zestawów. Slip przystosowany do bezpiecznego wodowania jednostek o masie do 5 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9961, 'Czynny', 'Dla klientów', 'W cenie usługi', 'Całodobowo', 'Asfaltowy', 'Strome', NULL, 2.5, 'Na terenie obiektu', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9962, 'Slip nad Notecią - Sarcz', 'slip-nad-notecia-sarcz-sarcz-9962', 'SLIP', 53.0576864, 16.4583623, 'Wielkopolskie', 'Sarcz', 'Dojazd do slipu drogą polną, w złym stanie, utrudniony po opadach. Nawierzchnia żwirowa, obecnie w remoncie, wymaga ostrożności. Brak dedykowanego miejsca na zestaw, parkowanie możliwe tylko na poboczu. Slip przeznaczony dla małych łodzi, nośność ograniczona do 1 tony.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9962, 'W remoncie', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Żwirowy', 'Umiarkowane', NULL, 1, 'Brak', FALSE, NULL, 'Wąsko', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9963, 'Slip rekreacyjny - Bronówek', 'slip-rekreacyjny-bronowek-bronowek-9963', 'SLIP', 50.9084834, 16.2375551, 'Dolnośląskie', 'Bronówek', 'Dojazd do slipu drogą prywatną, utwardzoną, dostępną tylko dla członków klubu. Nawierzchnia trawiasta, dobrze utrzymana, ale śliska po deszczu. Miejsce na zestaw dostępne na terenie klubu, jednak manewrowanie wymaga wprawy. Slip przeznaczony głównie dla kajaków i małych łodzi wiosłowych, nośność do 500 kg.', NULL);
