INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9964, 'Czynny', 'Publiczny', 'Bezpłatny', 'Całodobowo', 'Płyty betonowe', 'Umiarkowane', NULL, 1.2, 'Dostępny', TRUE, NULL, 'Dużo miejsca', NULL);
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (9965, 'Slip miejski - Warszawa Praga', 'slip-miejski-warszawa-praga-warszawa-9965', 'SLIP', 52.3264189, 20.9238692, 'Mazowieckie', 'Warszawa', 'Dojazd do slipu odbywa się wąską drogą osiedlową, wymagającą ostrożności. Nawierzchnia jest betonowa, w dobrym stanie, zapewniająca stabilne wodowanie. Miejsce na zestaw z przyczepą jest ograniczone, zaleca się wcześniejsze przygotowanie. Slip przystosowany jest do wodowania mniejszych i średnich jednostek, do 2 ton.', NULL);
INSERT INTO map_slips (id, status, access_type, fee_info, opening_hours, surface_type, incline, unit_limit, end_depth, trailer_parking, has_mooring_pier, lighting_and_monitoring, maneuvering_space, navigational_alerts) VALUES (9965, 'Czynny', 'Publiczny', 'Płatny', 'Całodobowo', 'Betonowy', 'Łagodne', NULL, 1, 'Ograniczony', FALSE, NULL, 'Wymaga wprawy', NULL);
